    #[cfg(feature = "network")]
    async fn handle_describe_vpc_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let vpc_id = match params.get("VpcId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'VpcId'"),
        };
        let attribute = match params.get("Attribute") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'Attribute'"),
        };

        let st = state.read().await;
        let vpc = match st.vpcs.get(&vpc_id) {
            Some(v) => v,
            None => {
                return ec2_error_response(&Ec2Error::VpcNotFound(vpc_id));
            }
        };

        // FIX(terraform-e2e): The terraform provider (v6.38+) calls DescribeVpcAttribute with
        // Attribute=enableNetworkAddressUsageMetrics. Returning an empty response causes the
        // provider to retry indefinitely (polling loop). Return false for unknown attributes.
        let mut result = DescribeVpcAttributeResult {
            vpc_id: Some(vpc_id),
            ..Default::default()
        };
        match attribute.as_str() {
            "enableDnsHostnames" => {
                result.enable_dns_hostnames = Some(AttributeBooleanValue {
                    value: Some(vpc.enable_dns_hostnames),
                });
            }
            "enableDnsSupport" => {
                result.enable_dns_support = Some(AttributeBooleanValue {
                    value: Some(vpc.enable_dns_support),
                });
            }
            "enableNetworkAddressUsageMetrics" => {
                result.enable_network_address_usage_metrics =
                    Some(AttributeBooleanValue { value: Some(false) });
            }
            _ => {}
        }
        wire::serialize_describe_vpc_attribute_response(&result)
    }

    #[cfg(feature = "network")]
    async fn handle_modify_vpc_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let vpc_id = match params.get("VpcId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'VpcId'"),
        };

        let mut st = state.write().await;
        if let Some(val_str) = params.get("EnableDnsHostnames.Value") {
            let val = val_str == "true" || val_str == "1";
            if let Err(e) = st.modify_vpc_attribute(&vpc_id, "enableDnsHostnames", val) {
                return ec2_error_response(&e);
            }
        } else if let Some(val_str) = params.get("EnableDnsSupport.Value") {
            let val = val_str == "true" || val_str == "1";
            if let Err(e) = st.modify_vpc_attribute(&vpc_id, "enableDnsSupport", val) {
                return ec2_error_response(&e);
            }
        }

        wire::serialize_modify_vpc_attribute_response()
    }

