    #[cfg(feature = "network")]
    async fn handle_describe_internet_gateways(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let st = state.read().await;
        let filters = parse_filters(params);
        let igw_id_params = parse_member_list(params, "InternetGatewayId");

        let igws: Vec<InternetGateway> = st
            .igws
            .values()
            .filter(|igw| {
                if !igw_id_params.is_empty() && !igw_id_params.contains(&igw.igw_id) {
                    return false;
                }
                for (name, values) in &filters {
                    match name.as_str() {
                        "internet-gateway-id" if !values.contains(&igw.igw_id) => {
                            return false;
                        }
                        "attachment.vpc-id" => {
                            let attached_vpcs: Vec<&str> =
                                igw.attachments.iter().map(|a| a.vpc_id.as_str()).collect();
                            if !values.iter().any(|v| attached_vpcs.contains(&v.as_str())) {
                                return false;
                            }
                        }
                        _ => {}
                    }
                }
                true
            })
            .map(igw_to_model)
            .collect();

        wire::serialize_describe_internet_gateways_response(&DescribeInternetGatewaysResult {
            internet_gateways: Some(InternetGatewayList { items: igws }),
            ..Default::default()
        })
    }

