    #[cfg(feature = "extras")]
    async fn handle_create_tags(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let resource_ids = parse_member_list(params, "ResourceId");
        let mut tags = Tags::new();
        let mut i = 1;
        loop {
            let k = format!("Tag.{i}.Key");
            let v = format!("Tag.{i}.Value");
            match (params.get(&k), params.get(&v)) {
                (Some(key), Some(val)) => {
                    tags.insert(key.clone(), val.clone());
                    i += 1;
                }
                _ => break,
            }
        }
        let mut st = state.write().await;
        st.create_tags(&resource_ids, &tags);
        wire::serialize_create_tags_response()
    }

    #[cfg(feature = "extras")]
    async fn handle_delete_tags(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let resource_ids = parse_member_list(params, "ResourceId");
        let mut tag_keys = Vec::new();
        let mut i = 1;
        loop {
            let k = format!("Tag.{i}.Key");
            match params.get(&k) {
                Some(key) => {
                    tag_keys.push(key.clone());
                    i += 1;
                }
                None => break,
            }
        }
        let mut st = state.write().await;
        st.delete_tags(&resource_ids, &tag_keys);
        wire::serialize_delete_tags_response()
    }

