    #[cfg(feature = "compute")]
    async fn handle_describe_key_pairs(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let st = state.read().await;
        let filters = parse_filters(params);
        let key_name_params = parse_member_list(params, "KeyName");

        let kps: Vec<KeyPairInfo> = st
            .key_pairs
            .values()
            .filter(|kp| {
                if !key_name_params.is_empty() && !key_name_params.contains(&kp.key_name) {
                    return false;
                }
                for (name, values) in &filters {
                    match name.as_str() {
                        "key-name" if !values.contains(&kp.key_name) => {
                            return false;
                        }
                        "key-pair-id" if !values.contains(&kp.key_pair_id) => {
                            return false;
                        }
                        _ => {}
                    }
                }
                true
            })
            .map(|kp| KeyPairInfo {
                key_name: Some(kp.key_name.clone()),
                key_fingerprint: Some(kp.fingerprint.clone()),
                key_pair_id: Some(kp.key_pair_id.clone()),
                tags: if kp.tags.is_empty() {
                    None
                } else {
                    Some(tags_to_model(&kp.tags))
                },
                ..Default::default()
            })
            .collect();

        wire::serialize_describe_key_pairs_response(&DescribeKeyPairsResult {
            key_pairs: Some(KeyPairList { items: kps }),
        })
    }

