    #[cfg(feature = "network")]
    async fn handle_describe_network_acls(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let st = state.read().await;
        let filters = parse_filters(params);
        let nacl_id_params = parse_member_list(params, "NetworkAclId");

        let acls: Vec<_> = st
            .network_acls
            .values()
            .filter(|acl| {
                if !nacl_id_params.is_empty() && !nacl_id_params.contains(&acl.network_acl_id) {
                    return false;
                }
                // Custom association.* filters are not field filters in the
                // shape that apply_filters_to_tags supports because they look
                // at related sub-records. Honour them explicitly here.
                for (name, values) in &filters {
                    match name.as_str() {
                        "association.subnet-id" => {
                            let any_match = acl
                                .associations
                                .iter()
                                .any(|a| values.contains(&a.subnet_id));
                            if !any_match {
                                return false;
                            }
                        }
                        "association.network-acl-id" => {
                            let any_match = acl
                                .associations
                                .iter()
                                .any(|a| values.contains(&a.network_acl_id));
                            if !any_match {
                                return false;
                            }
                        }
                        "association.association-id" => {
                            let any_match = acl
                                .associations
                                .iter()
                                .any(|a| values.contains(&a.network_acl_association_id));
                            if !any_match {
                                return false;
                            }
                        }
                        _ => {}
                    }
                }
                let scalar_filters: Vec<(String, Vec<String>)> = filters
                    .iter()
                    .filter(|(n, _)| {
                        !matches!(
                            n.as_str(),
                            "association.subnet-id"
                                | "association.network-acl-id"
                                | "association.association-id"
                        )
                    })
                    .cloned()
                    .collect();
                apply_filters_to_tags(
                    &acl.tags,
                    &scalar_filters,
                    &[
                        ("network-acl-id", Some(&acl.network_acl_id)),
                        ("vpc-id", Some(&acl.vpc_id)),
                        (
                            "default",
                            Some(if acl.is_default { "true" } else { "false" }),
                        ),
                    ],
                )
            })
            .map(nacl_to_model)
            .collect();

        wire::serialize_describe_network_acls_response(&DescribeNetworkAclsResult {
            network_acls: Some(acls.into()),
            ..Default::default()
        })
    }

