    #[cfg(feature = "network")]
    async fn handle_accept_address_transfer(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{AcceptAddressTransferResult, AddressTransfer as ModelAddressTransfer};
        let public_ip = match params.get("Address") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'Address'"),
        };
        let mut st = state.write().await;
        // Lookup transfer by public IP (the SDK passes the EIP's public address).
        let allocation_id = st
            .address_transfers
            .values()
            .find(|t| t.public_ip == public_ip)
            .map(|t| t.allocation_id.clone());
        match allocation_id {
            Some(alloc_id) => match st.accept_address_transfer(&alloc_id) {
                Ok(t) => {
                    let model = ModelAddressTransfer {
                        allocation_id: Some(t.allocation_id.clone()),
                        public_ip: Some(t.public_ip.clone()),
                        transfer_account_id: Some(t.transfer_account_id.clone()),
                        transfer_offer_expiration_timestamp: Some(
                            t.transfer_offer_expiration_timestamp.clone(),
                        ),
                        transfer_offer_accepted_timestamp: t
                            .transfer_offer_accepted_timestamp
                            .clone(),
                        address_transfer_status: Some(t.address_transfer_status.clone()),
                    };
                    wire::serialize_accept_address_transfer_response(&AcceptAddressTransferResult {
                        address_transfer: Some(model),
                    })
                }
                Err(e) => ec2_error_response(&e),
            },
            None => ec2_error_response(&Ec2Error::InvalidAddressTransferNotFound(public_ip)),
        }
    }

