    #[cfg(feature = "network")]
    async fn handle_provision_public_ipv4_pool_cidr(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            ProvisionPublicIpv4PoolCidrResult, PublicIpv4PoolRange as ModelPublicIpv4PoolRange,
        };
        let pool_id = match params.get("PoolId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'PoolId'"),
        };
        // The SDK passes either an existing IpamPoolId or a target Cidr; we
        // accept either for the mock and synthesise a plausible range. When
        // only an IPAM pool ID is given, we use a documentation-range CIDR
        // (192.0.2.0/n) so the resulting first/last addresses parse cleanly.
        let cidr = match params.get("Cidr") {
            Some(c) => c.clone(),
            None => {
                let nm = params
                    .get("NetmaskLength")
                    .and_then(|s| s.parse::<i32>().ok())
                    .unwrap_or(28);
                format!("192.0.2.0/{nm}")
            }
        };
        let netmask_length = params
            .get("NetmaskLength")
            .and_then(|s| s.parse::<i32>().ok())
            .unwrap_or(28);
        let mut st = state.write().await;
        match st.provision_public_ipv4_pool_cidr(&pool_id, &cidr, netmask_length) {
            Ok((_first, range)) => {
                let model_range = ModelPublicIpv4PoolRange {
                    first_address: Some(range.first_address.clone()),
                    last_address: Some(range.last_address.clone()),
                    address_count: Some(range.address_count),
                    available_address_count: Some(range.available_address_count),
                };
                wire::serialize_provision_public_ipv4_pool_cidr_response(
                    &ProvisionPublicIpv4PoolCidrResult {
                        pool_id: Some(pool_id),
                        pool_address_range: Some(model_range),
                    },
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

