    #[cfg(feature = "network")]
    async fn handle_describe_nat_gateways(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{NatGateway, NatGatewayAddress, NatGatewayAddressList, NatGatewayList};
        let st = state.read().await;
        let filters = parse_filters(params);
        let nat_id_params = parse_member_list(params, "NatGatewayId");

        // Check if a state filter is explicitly requested
        let has_state_filter = filters.iter().any(|(name, _)| name == "state");
        let nats: Vec<NatGateway> = st
            .nat_gateways
            .values()
            .filter(|nat| {
                // By default, exclude deleted NAT gateways (AWS behavior)
                if !has_state_filter && nat.state == "deleted" {
                    return false;
                }
                if !nat_id_params.is_empty() && !nat_id_params.contains(&nat.nat_gateway_id) {
                    return false;
                }
                apply_filters_to_tags(
                    &nat.tags,
                    &filters,
                    &[
                        ("nat-gateway-id", Some(&nat.nat_gateway_id)),
                        ("vpc-id", Some(&nat.vpc_id)),
                        ("subnet-id", Some(&nat.subnet_id)),
                        ("state", Some(&nat.state)),
                    ],
                )
            })
            .map(|nat| {
                let mut items: Vec<NatGatewayAddress> = if nat.connectivity_type == "public" {
                    vec![NatGatewayAddress {
                        allocation_id: nat.allocation_id.clone(),
                        public_ip: nat.public_ip.clone(),
                        is_primary: Some(true),
                        ..Default::default()
                    }]
                } else {
                    Vec::new()
                };
                for sa in &nat.secondary_addresses {
                    items.push(NatGatewayAddress {
                        allocation_id: sa.allocation_id.clone(),
                        association_id: sa.association_id.clone(),
                        network_interface_id: sa.network_interface_id.clone(),
                        private_ip: sa.private_ip.clone(),
                        public_ip: sa.public_ip.clone(),
                        status: Some(sa.status.clone()),
                        is_primary: Some(false),
                        ..Default::default()
                    });
                }
                let nat_addrs = if items.is_empty() {
                    None
                } else {
                    Some(NatGatewayAddressList { items })
                };
                NatGateway {
                    nat_gateway_id: Some(nat.nat_gateway_id.clone()),
                    vpc_id: Some(nat.vpc_id.clone()),
                    subnet_id: Some(nat.subnet_id.clone()),
                    state: Some(nat.state.clone()),
                    connectivity_type: Some(nat.connectivity_type.clone()),
                    nat_gateway_addresses: nat_addrs,
                    tags: if nat.tags.is_empty() {
                        None
                    } else {
                        Some(tags_to_model(&nat.tags))
                    },
                    ..Default::default()
                }
            })
            .collect();

        wire::serialize_describe_nat_gateways_response(&DescribeNatGatewaysResult {
            nat_gateways: Some(NatGatewayList { items: nats }),
            ..Default::default()
        })
    }

