    // Well-known AWS VPC endpoint services for the requested region.
    #[cfg(feature = "network")]
    async fn handle_describe_vpc_endpoint_services(&self, region: &str) -> MockResponse {
        use crate::model::{
            DescribeVpcEndpointServicesResult, ServiceDetail, ServiceDetailSet, ServiceTypeDetail,
            ServiceTypeDetailSet, ValueStringList,
        };
        // (short_name, service_type)
        let catalogue: &[(&str, &str)] = &[
            ("s3", "Gateway"),
            ("dynamodb", "Gateway"),
            ("ec2", "Interface"),
            ("kms", "Interface"),
            ("sts", "Interface"),
        ];
        let names: Vec<String> = catalogue
            .iter()
            .map(|(n, _)| format!("com.amazonaws.{region}.{n}"))
            .collect();
        let details: Vec<ServiceDetail> = catalogue
            .iter()
            .map(|(n, ty)| ServiceDetail {
                service_name: Some(format!("com.amazonaws.{region}.{n}")),
                service_id: Some(format!("vpce-svc-{n}-mock")),
                owner: Some("amazon".to_string()),
                acceptance_required: Some(false),
                manages_vpc_endpoints: Some(false),
                service_region: Some(region.to_string()),
                service_type: Some(ServiceTypeDetailSet {
                    items: vec![ServiceTypeDetail {
                        service_type: Some((*ty).to_string()),
                    }],
                }),
                ..Default::default()
            })
            .collect();
        wire::serialize_describe_vpc_endpoint_services_response(
            &DescribeVpcEndpointServicesResult {
                service_names: Some(ValueStringList { items: names }),
                service_details: Some(ServiceDetailSet { items: details }),
                next_token: None,
            },
        )
    }

