    #[cfg(feature = "extras")]
    async fn handle_describe_ec2_tags(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{TagDescription, TagDescriptionList};
        let st = state.read().await;
        let filters = parse_filters(params);

        // Collect all tags from all resources
        let mut all_tags: Vec<(String, String, String, String)> = Vec::new();

        let add_tags = |id: &str, res_type: &str, tags: &Tags, all_tags: &mut Vec<_>| {
            for (k, v) in tags {
                all_tags.push((id.to_string(), res_type.to_string(), k.clone(), v.clone()));
            }
        };

        for (id, vpc) in &st.vpcs {
            add_tags(id, "vpc", &vpc.tags, &mut all_tags);
        }
        for (id, subnet) in &st.subnets {
            add_tags(id, "subnet", &subnet.tags, &mut all_tags);
        }
        for (id, igw) in &st.igws {
            add_tags(id, "internet-gateway", &igw.tags, &mut all_tags);
        }
        for (id, sg) in &st.security_groups {
            add_tags(id, "security-group", &sg.tags, &mut all_tags);
        }
        for (id, rtb) in &st.route_tables {
            add_tags(id, "route-table", &rtb.tags, &mut all_tags);
        }

        // Apply filters
        let items: Vec<TagDescription> = all_tags
            .iter()
            .filter(|(res_id, res_type, key, val)| {
                for (name, values) in &filters {
                    match name.as_str() {
                        "resource-id" if !values.contains(res_id) => {
                            return false;
                        }
                        "resource-type" if !values.contains(res_type) => {
                            return false;
                        }
                        "key" if !values.contains(key) => {
                            return false;
                        }
                        "value" if !values.contains(val) => {
                            return false;
                        }
                        _ => {}
                    }
                }
                true
            })
            .map(|(res_id, res_type, key, val)| TagDescription {
                resource_id: Some(res_id.clone()),
                resource_type: Some(res_type.clone()),
                key: Some(key.clone()),
                value: Some(val.clone()),
            })
            .collect();

        wire::serialize_describe_tags_response(&DescribeTagsResult {
            tags: Some(TagDescriptionList { items }),
            ..Default::default()
        })
    }

    // --- Instance handlers ---

    #[cfg(feature = "compute")]
    async fn handle_run_instances(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
        region: &str,
    ) -> MockResponse {
        use crate::model::{GroupIdentifierList, Reservation};

        let image_id = params.get("ImageId").cloned().unwrap_or_default();
        let instance_type = params
            .get("InstanceType")
            .cloned()
            .unwrap_or_else(|| "t2.micro".to_string());
        let min_count = params
            .get("MinCount")
            .and_then(|s| s.parse().ok())
            .unwrap_or(1i32);
        let max_count = params
            .get("MaxCount")
            .and_then(|s| s.parse().ok())
            .unwrap_or(1i32);
        let key_name = params.get("KeyName").cloned();
        let subnet_id = params.get("SubnetId").cloned();
        let tags = parse_tag_specifications(params, "instance");
        let iam_instance_profile_arn = params.get("IamInstanceProfile.Arn").cloned();
        let az = params
            .get("Placement.AvailabilityZone")
            .cloned()
            .unwrap_or_else(|| format!("{region}a"));

        // Collect security group IDs
        let mut sg_ids = Vec::new();
        let mut n = 1;
        loop {
            let key = format!("SecurityGroupId.{n}");
            match params.get(&key) {
                Some(v) => {
                    sg_ids.push(v.clone());
                    n += 1;
                }
                None => break,
            }
        }

        let mut st = state.write().await;
        let instances = st.run_instances(
            &image_id,
            &instance_type,
            min_count,
            max_count,
            key_name,
            subnet_id,
            sg_ids,
            tags,
            iam_instance_profile_arn,
            &az,
            account_id,
        );

        let reservation_id = format!("r-{:08x}", uuid::Uuid::new_v4().as_u128() as u32);
        let model_instances: Vec<crate::model::Instance> =
            instances.iter().map(instance_to_model).collect();

        let reservation = Reservation {
            reservation_id: Some(reservation_id),
            owner_id: Some(account_id.to_string()),
            groups: Some(GroupIdentifierList { items: vec![] }),
            instances: Some(model_instances.into()),
            requester_id: None,
        };
        wire::serialize_run_instances_response(&reservation)
    }

