    // --- EBS Volume handlers ---

    #[cfg(feature = "storage")]
    async fn handle_create_volume(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        region: &str,
    ) -> MockResponse {
        let az = params
            .get("AvailabilityZone")
            .cloned()
            .unwrap_or_else(|| format!("{region}a"));
        let snapshot_id = params.get("SnapshotId").cloned();
        let explicit_size: Option<i32> = params.get("Size").and_then(|s| s.parse().ok());
        let volume_type = params
            .get("VolumeType")
            .cloned()
            .unwrap_or_else(|| "gp2".to_string());
        let iops = params.get("Iops").and_then(|s| s.parse().ok());
        let throughput = params.get("Throughput").and_then(|s| s.parse().ok());
        let explicit_encrypted: Option<bool> = params.get("Encrypted").map(|s| s == "true");
        let tags = parse_tag_specifications(params, "volume");

        let mut st = state.write().await;
        // AWS: if Size is omitted while restoring from a snapshot, the new
        // volume inherits the snapshot's source volume size.
        let size = explicit_size
            .or_else(|| {
                snapshot_id
                    .as_ref()
                    .and_then(|sid| st.snapshots.get(sid).map(|s| s.volume_size))
            })
            .unwrap_or(8i32);
        // AWS: account-wide EBS encryption-by-default applies when the
        // request omits Encrypted. An explicit value still wins.
        let encrypted = explicit_encrypted.unwrap_or(st.ebs_encryption_by_default);
        let vol = st.create_volume(
            size,
            &az,
            snapshot_id,
            &volume_type,
            iops,
            throughput,
            encrypted,
            tags,
        );
        wire::serialize_create_volume_response(&volume_to_model(vol))
    }

