    #[cfg(feature = "compute")]
    async fn handle_describe_images(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
    ) -> MockResponse {
        use crate::model::{DescribeImagesResult, ImageList};
        let st = state.read().await;
        let image_id_params = parse_member_list(params, "ImageId");
        let owner_params = parse_member_list(params, "Owner");
        let filters = parse_filters(params);

        let found_images: Vec<crate::model::Image> = st
            .images
            .values()
            .filter(|img| {
                // Hide images that are sitting in the recycle bin from
                // DescribeImages, mirroring the AWS contract.
                if img.recycle_bin_state.as_deref() == Some("recycled") {
                    return false;
                }
                if !image_id_params.is_empty() && !image_id_params.contains(&img.image_id) {
                    return false;
                }
                if !owner_params.is_empty() {
                    let matches_owner = owner_params
                        .iter()
                        .any(|o| o == "self" || o == account_id || o == &img.owner_id);
                    if !matches_owner {
                        return false;
                    }
                }
                apply_filters_to_tags(
                    &img.tags,
                    &filters,
                    &[
                        ("image-id", Some(&img.image_id)),
                        ("state", Some(&img.state)),
                        ("name", Some(&img.name)),
                        ("owner-id", Some(&img.owner_id)),
                    ],
                )
            })
            .map(image_to_model)
            .collect();

        // When specific image IDs were requested and none were found in state,
        // synthesise stub AMIs so provider code that calls DescribeImages for
        // validation (e.g. aws_launch_configuration root-device lookup) does not
        // see an empty result.
        let images = if !image_id_params.is_empty()
            && found_images.is_empty()
            && owner_params.is_empty()
            && filters.is_empty()
            && !image_id_params
                .iter()
                .any(|id| st.deregistered_images.contains(id))
        {
            image_id_params
                .iter()
                .map(|id| crate::model::Image {
                    image_id: Some(id.clone()),
                    state: Some("available".to_string()),
                    root_device_name: Some("/dev/xvda".to_string()),
                    root_device_type: Some("ebs".to_string()),
                    architecture: Some("x86_64".to_string()),
                    image_type: Some("machine".to_string()),
                    public: Some(true),
                    owner_id: Some(account_id.to_string()),
                    name: Some(id.clone()),
                    ..Default::default()
                })
                .collect()
        } else {
            found_images
        };

        wire::serialize_describe_images_response(&DescribeImagesResult {
            images: Some(ImageList { items: images }),
            next_token: None,
        })
    }

