    #[cfg(feature = "compute")]
    async fn handle_describe_image_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            AttributeValue as ModelAttributeValue, ImageAttribute,
            LaunchPermission as ModelLaunchPermission, LaunchPermissionList,
        };
        let image_id = match params.get("ImageId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'ImageId'"),
        };
        let attribute = match params.get("Attribute") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'Attribute'"),
        };
        let st = state.read().await;
        let img = match st.get_image(&image_id) {
            Ok(img) => img,
            Err(e) => return ec2_error_response(&e),
        };
        let mut result = ImageAttribute {
            image_id: Some(image_id.clone()),
            ..Default::default()
        };
        match attribute.as_str() {
            "description" => {
                result.description = Some(ModelAttributeValue {
                    value: Some(img.description.clone()),
                });
            }
            "launchPermission" => {
                let items: Vec<ModelLaunchPermission> = img
                    .launch_permissions
                    .iter()
                    .map(|p| ModelLaunchPermission {
                        group: p.group.clone(),
                        user_id: p.user_id.clone(),
                        ..Default::default()
                    })
                    .collect();
                result.launch_permissions = Some(LaunchPermissionList { items });
            }
            "kernel" => {
                result.kernel_id = Some(ModelAttributeValue { value: None });
            }
            "ramdisk" => {
                result.ramdisk_id = Some(ModelAttributeValue { value: None });
            }
            "blockDeviceMapping"
            | "productCodes"
            | "sriovNetSupport"
            | "bootMode"
            | "tpmSupport"
            | "uefiData"
            | "lastLaunchedTime"
            | "imdsSupport"
            | "deregistrationProtection" => {
                // Return image_id only — no payload modelled for these attributes.
            }
            _ => {
                return MockResponse::error(
                    400,
                    "InvalidParameterValue",
                    &format!("Invalid attribute '{attribute}'"),
                );
            }
        }
        wire::serialize_describe_image_attribute_response(&result)
    }

    #[cfg(feature = "compute")]
    async fn handle_modify_image_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let image_id = match params.get("ImageId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'ImageId'"),
        };

        let attribute = params.get("Attribute").cloned();
        let value = params.get("Value").cloned();
        let operation_type = params.get("OperationType").cloned();

        let mut st = state.write().await;

        // Description: prefer the structured Description.Value, fall back to
        // legacy Attribute=description / Value=... shorthand.
        if let Some(desc) = params.get("Description.Value").cloned() {
            if let Err(e) = st.modify_image_description(&image_id, &desc) {
                return ec2_error_response(&e);
            }
        } else if attribute.as_deref() == Some("description")
            && let Some(v) = value.as_ref()
            && let Err(e) = st.modify_image_description(&image_id, v)
        {
            return ec2_error_response(&e);
        }

        // Launch permission: structured form (LaunchPermission.Add.N.UserId, ...)
        let mut adds: Vec<crate::types::LaunchPermission> = Vec::new();
        let mut removes: Vec<crate::types::LaunchPermission> = Vec::new();
        collect_launch_permissions(params, "Add", &mut adds);
        collect_launch_permissions(params, "Remove", &mut removes);

        // Legacy shorthand: Attribute=launchPermission, OperationType=add|remove,
        // UserId.N=..., UserGroup.N=...
        if attribute.as_deref() == Some("launchPermission") {
            let user_ids = parse_member_list(params, "UserId");
            let user_groups = parse_member_list(params, "UserGroup");
            let perms: Vec<crate::types::LaunchPermission> = user_ids
                .into_iter()
                .map(|uid| crate::types::LaunchPermission {
                    user_id: Some(uid),
                    group: None,
                })
                .chain(
                    user_groups
                        .into_iter()
                        .map(|g| crate::types::LaunchPermission {
                            user_id: None,
                            group: Some(g),
                        }),
                )
                .collect();
            match operation_type.as_deref() {
                Some("add") => adds.extend(perms),
                Some("remove") => removes.extend(perms),
                _ => {}
            }
        }

        if !adds.is_empty() || !removes.is_empty() {
            if let Err(e) = st.modify_image_launch_permissions(&image_id, &adds, &removes) {
                return ec2_error_response(&e);
            }
        }

        wire::serialize_modify_image_attribute_response()
    }

