    #[cfg(feature = "network")]
    async fn handle_describe_security_group_rules(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let st = state.read().await;
        let filters = parse_filters(params);
        let group_id_filter = filters
            .iter()
            .find(|(n, _)| n == "group-id")
            .and_then(|(_, v)| v.first().cloned());
        let rule_ids = parse_member_list(params, "SecurityGroupRuleId");
        let rules = st.describe_security_group_rules(group_id_filter.as_deref(), &rule_ids);
        use crate::model::{
            DescribeSecurityGroupRulesResult, SecurityGroupRule as ModelSgRule,
            SecurityGroupRuleList,
        };
        let rule_items: Vec<ModelSgRule> = rules
            .iter()
            .map(|(gid, is_egress, rule)| ModelSgRule {
                security_group_rule_id: Some(rule.rule_id.clone()),
                group_id: Some(gid.to_string()),
                is_egress: Some(*is_egress),
                ip_protocol: Some(rule.ip_protocol.clone()),
                from_port: rule.from_port.map(|p| p as i32),
                to_port: rule.to_port.map(|p| p as i32),
                cidr_ipv4: rule.ip_ranges.first().map(|r| r.cidr_ip.clone()),
                ..Default::default()
            })
            .collect();
        wire::serialize_describe_security_group_rules_response(&DescribeSecurityGroupRulesResult {
            security_group_rules: Some(SecurityGroupRuleList { items: rule_items }),
            ..Default::default()
        })
    }

    #[cfg(feature = "network")]
    async fn handle_update_sg_rule_descriptions_ingress(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let group_id = match params.get("GroupId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'GroupId'"),
        };
        let mut st = state.write().await;
        let mut n = 1;
        loop {
            let rule_id_key = format!("IpPermissions.{n}.SecurityGroupRuleId");
            match params.get(&rule_id_key) {
                Some(rule_id) => {
                    let desc_key = format!("IpPermissions.{n}.IpRanges.1.Description");
                    let desc = params.get(&desc_key).cloned();
                    let _ = st.update_sgr_description_ingress(&group_id, rule_id, desc);
                    n += 1;
                }
                None => break,
            }
        }
        use crate::model::UpdateSecurityGroupRuleDescriptionsIngressResult;
        wire::serialize_update_security_group_rule_descriptions_ingress_response(
            &UpdateSecurityGroupRuleDescriptionsIngressResult {
                r#return: Some(true),
            },
        )
    }

