    #[cfg(feature = "network")]
    async fn handle_create_flow_logs(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let traffic_type = params
            .get("TrafficType")
            .cloned()
            .unwrap_or_else(|| "ALL".to_string());
        let log_dest_type = params
            .get("LogDestinationType")
            .cloned()
            .unwrap_or_else(|| "cloud-watch-logs".to_string());
        let log_dest = params.get("LogDestination").cloned();
        let log_group = params.get("LogGroupName").cloned();
        let tags = parse_tag_specifications(params, "vpc-flow-log");
        let resource_ids = parse_member_list(params, "ResourceId");
        let mut st = state.write().await;
        use crate::model::{CreateFlowLogsResult, ValueStringList};
        let mut flow_log_ids = Vec::new();
        for resource_id in &resource_ids {
            let id = st.create_flow_log(
                resource_id,
                &traffic_type,
                &log_dest_type,
                log_dest.clone(),
                log_group.clone(),
                tags.clone(),
            );
            flow_log_ids.push(id);
        }
        wire::serialize_create_flow_logs_response(&CreateFlowLogsResult {
            flow_log_ids: Some(ValueStringList {
                items: flow_log_ids,
            }),
            ..Default::default()
        })
    }

    #[cfg(feature = "network")]
    async fn handle_delete_flow_logs(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            DeleteFlowLogsResult, UnsuccessfulItem, UnsuccessfulItemError, UnsuccessfulItemSet,
        };
        let ids = parse_member_list(params, "FlowLogId");
        let mut st = state.write().await;
        let mut unsuccessful: Vec<UnsuccessfulItem> = Vec::new();
        for id in &ids {
            if st.flow_logs.remove(id).is_none() {
                unsuccessful.push(UnsuccessfulItem {
                    resource_id: Some(id.clone()),
                    error: Some(UnsuccessfulItemError {
                        code: Some("InvalidFlowLogId.NotFound".to_string()),
                        message: Some(format!("The flow log '{id}' does not exist")),
                    }),
                });
            }
        }
        let unsuccessful_set = if unsuccessful.is_empty() {
            None
        } else {
            Some(UnsuccessfulItemSet {
                items: unsuccessful,
            })
        };
        wire::serialize_delete_flow_logs_response(&DeleteFlowLogsResult {
            unsuccessful: unsuccessful_set,
        })
    }

