    // VPC peering connection options (DNS resolution, etc.) are accepted but the
    // mock does not enforce peering-level routing; returns success.
    #[cfg(feature = "network")]
    async fn handle_modify_vpc_peering_options(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{ModifyVpcPeeringConnectionOptionsResult, PeeringConnectionOptions};
        use crate::types::VpcPeeringConnectionOptions;
        let id = match params.get("VpcPeeringConnectionId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'VpcPeeringConnectionId'",
                );
            }
        };
        let parse_opts = |prefix: &str| -> Option<VpcPeeringConnectionOptions> {
            let dns = params
                .get(&format!("{prefix}.AllowDnsResolutionFromRemoteVpc"))
                .and_then(|s| s.parse::<bool>().ok());
            let cl = params
                .get(&format!(
                    "{prefix}.AllowEgressFromLocalClassicLinkToRemoteVpc"
                ))
                .and_then(|s| s.parse::<bool>().ok());
            let cl2 = params
                .get(&format!(
                    "{prefix}.AllowEgressFromLocalVpcToRemoteClassicLink"
                ))
                .and_then(|s| s.parse::<bool>().ok());
            if dns.is_none() && cl.is_none() && cl2.is_none() {
                None
            } else {
                Some(VpcPeeringConnectionOptions {
                    allow_dns_resolution_from_remote_vpc: dns.unwrap_or(false),
                    allow_egress_from_local_classic_link_to_remote_vpc: cl.unwrap_or(false),
                    allow_egress_from_local_vpc_to_remote_classic_link: cl2.unwrap_or(false),
                })
            }
        };
        let req = parse_opts("RequesterPeeringConnectionOptions");
        let acc = parse_opts("AccepterPeeringConnectionOptions");
        let mut st = state.write().await;
        let conn = match st.vpc_peering_connections.get_mut(&id) {
            Some(c) => c,
            None => return ec2_error_response(&Ec2Error::VpcPeeringConnectionNotFound(id)),
        };
        if let Some(o) = req.clone() {
            conn.requester_peering_options = Some(o);
        }
        if let Some(o) = acc.clone() {
            conn.accepter_peering_options = Some(o);
        }
        let to_model = |o: &VpcPeeringConnectionOptions| PeeringConnectionOptions {
            allow_dns_resolution_from_remote_vpc: Some(o.allow_dns_resolution_from_remote_vpc),
            allow_egress_from_local_classic_link_to_remote_vpc: Some(
                o.allow_egress_from_local_classic_link_to_remote_vpc,
            ),
            allow_egress_from_local_vpc_to_remote_classic_link: Some(
                o.allow_egress_from_local_vpc_to_remote_classic_link,
            ),
        };
        wire::serialize_modify_vpc_peering_connection_options_response(
            &ModifyVpcPeeringConnectionOptionsResult {
                requester_peering_connection_options: conn
                    .requester_peering_options
                    .as_ref()
                    .map(to_model),
                accepter_peering_connection_options: conn
                    .accepter_peering_options
                    .as_ref()
                    .map(to_model),
            },
        )
    }

