    #[cfg(feature = "network")]
    async fn handle_delete_vpc_endpoints(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            DeleteVpcEndpointsResult, UnsuccessfulItem, UnsuccessfulItemError, UnsuccessfulItemSet,
        };
        let ids = parse_member_list(params, "VpcEndpointId");
        let mut st = state.write().await;
        let mut unsuccessful: Vec<UnsuccessfulItem> = Vec::new();
        for id in &ids {
            if st.vpc_endpoints.remove(id).is_none() {
                unsuccessful.push(UnsuccessfulItem {
                    resource_id: Some(id.clone()),
                    error: Some(UnsuccessfulItemError {
                        code: Some("InvalidVpcEndpointId.NotFound".to_string()),
                        message: Some(format!("The endpoint '{id}' does not exist")),
                    }),
                });
            }
        }
        let unsuccessful_set = if unsuccessful.is_empty() {
            None
        } else {
            Some(UnsuccessfulItemSet {
                items: unsuccessful,
            })
        };
        wire::serialize_delete_vpc_endpoints_response(&DeleteVpcEndpointsResult {
            unsuccessful: unsuccessful_set,
        })
    }

