    // --- Managed prefix list handlers ---

    #[cfg(feature = "network")]
    async fn handle_create_managed_prefix_list(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let name = match params.get("PrefixListName") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'PrefixListName'");
            }
        };
        let max_entries = params
            .get("MaxEntries")
            .and_then(|s| s.parse().ok())
            .unwrap_or(10i32);
        let address_family = params
            .get("AddressFamily")
            .cloned()
            .unwrap_or_else(|| "IPv4".to_string());
        let tags = parse_tag_specifications(params, "prefix-list");
        let mut entries = Vec::new();
        let mut n = 1;
        loop {
            let cidr_key = format!("Entry.{n}.Cidr");
            match params.get(&cidr_key) {
                Some(cidr) => {
                    let desc = params.get(&format!("Entry.{n}.Description")).cloned();
                    entries.push(crate::types::TypesPrefixListEntry {
                        cidr: cidr.clone(),
                        description: desc,
                    });
                    n += 1;
                }
                None => break,
            }
        }
        let mut st = state.write().await;
        let pl = st.create_managed_prefix_list(&name, max_entries, &address_family, entries, tags);
        use crate::model::{CreateManagedPrefixListResult, ManagedPrefixList as ModelPl};
        wire::serialize_create_managed_prefix_list_response(&CreateManagedPrefixListResult {
            prefix_list: Some(ModelPl {
                prefix_list_id: Some(pl.prefix_list_id.clone()),
                prefix_list_name: Some(pl.prefix_list_name.clone()),
                state: Some("create-complete".to_string()),
                address_family: Some(pl.address_family.clone()),
                max_entries: Some(pl.max_entries),
                version: Some(pl.version),
                ..Default::default()
            }),
        })
    }

