    #[cfg(feature = "network")]
    async fn handle_modify_managed_prefix_list(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let id = match params.get("PrefixListId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'PrefixListId'"),
        };
        let mut add_entries = Vec::new();
        let mut n = 1;
        loop {
            let cidr_key = format!("AddEntry.{n}.Cidr");
            match params.get(&cidr_key) {
                Some(cidr) => {
                    let desc = params.get(&format!("AddEntry.{n}.Description")).cloned();
                    add_entries.push(crate::types::TypesPrefixListEntry {
                        cidr: cidr.clone(),
                        description: desc,
                    });
                    n += 1;
                }
                None => break,
            }
        }
        let mut remove_cidrs = Vec::new();
        let mut n = 1;
        loop {
            let cidr_key = format!("RemoveEntry.{n}.Cidr");
            match params.get(&cidr_key) {
                Some(cidr) => {
                    remove_cidrs.push(cidr.clone());
                    n += 1;
                }
                None => break,
            }
        }
        let mut st = state.write().await;
        match st.modify_managed_prefix_list(&id, add_entries, remove_cidrs) {
            Ok(()) => {
                use crate::model::ModifyManagedPrefixListResult;
                wire::serialize_modify_managed_prefix_list_response(
                    &ModifyManagedPrefixListResult::default(),
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

