    #[cfg(feature = "advanced-network")]
    async fn handle_create_customer_gateway(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let bgp_asn = params
            .get("BgpAsn")
            .cloned()
            .unwrap_or_else(|| "65000".to_string());
        let ip_address = params.get("IpAddress").cloned().unwrap_or_default();
        let gateway_type = params
            .get("Type")
            .cloned()
            .unwrap_or_else(|| "ipsec.1".to_string());
        let tags = parse_tag_specifications(params, "customer-gateway");
        let mut st = state.write().await;
        let cgw = st.create_customer_gateway(&bgp_asn, &ip_address, &gateway_type, tags);
        use crate::model::{CreateCustomerGatewayResult, CustomerGateway as ModelCgw};
        // FIX(terraform-e2e): aws_customer_gateway with tags requires the create response
        // to echo tags back so the provider doesn't see drift on the next refresh.
        let tag_set = if cgw.tags.is_empty() {
            None
        } else {
            Some(tags_to_model(&cgw.tags))
        };
        wire::serialize_create_customer_gateway_response(&CreateCustomerGatewayResult {
            customer_gateway: Some(ModelCgw {
                customer_gateway_id: Some(cgw.customer_gateway_id.clone()),
                state: Some("available".to_string()),
                r#type: Some(gateway_type.clone()),
                ip_address: Some(ip_address.clone()),
                bgp_asn: Some(bgp_asn.clone()),
                tags: tag_set,
                ..Default::default()
            }),
        })
    }

