    // --- Network interface handlers ---

    #[cfg(feature = "network")]
    async fn handle_describe_network_interfaces_stateful(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let st = state.read().await;
        use crate::model::{
            DescribeNetworkInterfacesResult, NetworkInterface as ModelEni,
            NetworkInterfaceAttachment, NetworkInterfaceList,
        };
        let ids = parse_member_list(params, "NetworkInterfaceId");
        let eni_items: Vec<ModelEni> = st
            .network_interfaces
            .values()
            .filter(|eni| ids.is_empty() || ids.contains(&eni.network_interface_id))
            .map(|eni| ModelEni {
                network_interface_id: Some(eni.network_interface_id.clone()),
                subnet_id: Some(eni.subnet_id.clone()),
                vpc_id: Some(eni.vpc_id.clone()),
                description: Some(eni.description.clone()),
                private_ip_address: Some(eni.private_ip_address.clone()),
                status: Some(eni.status.clone()),
                source_dest_check: Some(eni.source_dest_check),
                attachment: eni
                    .attachment_id
                    .as_ref()
                    .map(|aid| NetworkInterfaceAttachment {
                        attachment_id: Some(aid.clone()),
                        instance_id: eni.instance_id.clone(),
                        status: Some("attached".to_string()),
                        ..Default::default()
                    }),
                ..Default::default()
            })
            .collect();
        wire::serialize_describe_network_interfaces_response(&DescribeNetworkInterfacesResult {
            network_interfaces: Some(NetworkInterfaceList { items: eni_items }),
            ..Default::default()
        })
    }

