    #[cfg(feature = "network")]
    async fn handle_modify_network_interface_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let eni_id = match params.get("NetworkInterfaceId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'NetworkInterfaceId'",
                );
            }
        };
        let mut st = state.write().await;
        match st.network_interfaces.get_mut(&eni_id) {
            Some(eni) => {
                if let Some(desc) = params.get("Description.Value") {
                    eni.description = desc.clone();
                }
                let sg_ids = parse_member_list(params, "SecurityGroupId");
                if !sg_ids.is_empty() {
                    eni.security_groups = sg_ids;
                }
                if let Some(sdc) = params.get("SourceDestCheck.Value") {
                    eni.source_dest_check = sdc == "true";
                }
                wire::serialize_modify_network_interface_attribute_response()
            }
            None => ec2_error_response(&Ec2Error::NetworkInterfaceNotFound(eni_id)),
        }
    }

    #[cfg(feature = "network")]
    async fn handle_assign_private_ip_addresses(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::AssignPrivateIpAddressesResult;
        let eni_id = params
            .get("NetworkInterfaceId")
            .cloned()
            .unwrap_or_default();
        let st = state.read().await;
        if !st.network_interfaces.contains_key(&eni_id) {
            return ec2_error_response(&Ec2Error::NetworkInterfaceNotFound(eni_id));
        }
        // Private IP accounting is accepted but secondary IPs are not
        // individually tracked on the ENI; return success.
        wire::serialize_assign_private_ip_addresses_response(
            &AssignPrivateIpAddressesResult::default(),
        )
    }

