    // --- Additional instance operation handlers ---

    #[cfg(feature = "compute")]
    async fn handle_describe_instance_status(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            DescribeInstanceStatusResult, InstanceState as ModelInstanceState,
            InstanceStatus as ModelInstanceStatus, InstanceStatusList, InstanceStatusSummary,
        };
        let st = state.read().await;
        let ids = parse_member_list(params, "InstanceId");
        let status_items: Vec<ModelInstanceStatus> = st
            .instances
            .values()
            .filter(|i| ids.is_empty() || ids.contains(&i.instance_id))
            .filter(|i| i.state.name == "running")
            .map(|i| ModelInstanceStatus {
                instance_id: Some(i.instance_id.clone()),
                instance_state: Some(ModelInstanceState {
                    code: Some(16),
                    name: Some("running".to_string()),
                }),
                system_status: Some(InstanceStatusSummary {
                    status: Some("ok".to_string()),
                    ..Default::default()
                }),
                instance_status: Some(InstanceStatusSummary {
                    status: Some("ok".to_string()),
                    ..Default::default()
                }),
                ..Default::default()
            })
            .collect();
        wire::serialize_describe_instance_status_response(&DescribeInstanceStatusResult {
            instance_statuses: Some(InstanceStatusList {
                items: status_items,
            }),
            ..Default::default()
        })
    }

    #[cfg(feature = "compute")]
    async fn handle_describe_instance_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let instance_id = params.get("InstanceId").cloned().unwrap_or_default();
        let attribute = params.get("Attribute").cloned().unwrap_or_default();
        let st = state.read().await;
        use crate::model::{AttributeBooleanValue, AttributeValue, InstanceAttribute};
        let mut result = InstanceAttribute {
            instance_id: Some(instance_id.clone()),
            ..Default::default()
        };
        if let Some(inst) = st.instances.get(&instance_id) {
            match attribute.as_str() {
                "instanceType" => {
                    result.instance_type = Some(AttributeValue {
                        value: Some(inst.instance_type.clone()),
                    });
                }
                "userData" => {
                    result.user_data = Some(AttributeValue { value: None });
                }
                "disableApiTermination" => {
                    result.disable_api_termination =
                        Some(AttributeBooleanValue { value: Some(false) });
                }
                _ => {}
            }
        }
        wire::serialize_describe_instance_attribute_response(&result)
    }

