    // Walk the static instance-type catalogue used by `DescribeInstanceTypes`
    // and emit one offering per type at the requested location.
    #[cfg(feature = "compute")]
    async fn handle_describe_instance_type_offerings(
        &self,
        params: &HashMap<String, String>,
        region: &str,
    ) -> MockResponse {
        use crate::model::{
            DescribeInstanceTypeOfferingsResult, InstanceTypeOffering, InstanceTypeOfferingsList,
        };
        let catalogue: &[&str] = &[
            "t2.micro",
            "t2.small",
            "t3.micro",
            "t3.small",
            "t3.medium",
            "t3.large",
            "m5.large",
            "m5.xlarge",
            "m5.2xlarge",
            "c5.large",
            "c5.xlarge",
            "r5.large",
        ];
        let location_type = params
            .get("LocationType")
            .cloned()
            .unwrap_or_else(|| "region".to_string());
        let requested = parse_member_list(params, "InstanceType");
        let items: Vec<InstanceTypeOffering> = catalogue
            .iter()
            .filter(|t| requested.is_empty() || requested.iter().any(|r| r == *t))
            .map(|t| InstanceTypeOffering {
                instance_type: Some((*t).to_string()),
                location_type: Some(location_type.clone()),
                location: Some(region.to_string()),
            })
            .collect();
        wire::serialize_describe_instance_type_offerings_response(
            &DescribeInstanceTypeOfferingsResult {
                instance_type_offerings: Some(InstanceTypeOfferingsList { items }),
                next_token: None,
            },
        )
    }

