    #[cfg(feature = "storage")]
    async fn handle_modify_volume(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::ModifyVolumeResult;
        let vol_id = match params.get("VolumeId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'VolumeId'"),
        };
        let new_size = params.get("Size").and_then(|s| s.parse::<i32>().ok());
        let new_volume_type = params.get("VolumeType").cloned();
        let new_iops = params.get("Iops").and_then(|s| s.parse::<i32>().ok());
        let new_throughput = params.get("Throughput").and_then(|s| s.parse::<i32>().ok());
        let new_multi_attach = params
            .get("MultiAttachEnabled")
            .and_then(|s| s.parse::<bool>().ok());
        let mut st = state.write().await;
        match st.modify_volume(
            &vol_id,
            new_size,
            new_volume_type,
            new_iops,
            new_throughput,
            new_multi_attach,
        ) {
            Ok(modification) => {
                let model = volume_modification_to_model(modification);
                wire::serialize_modify_volume_response(&ModifyVolumeResult {
                    volume_modification: Some(model),
                })
            }
            Err(e) => ec2_error_response(&e),
        }
    }

