    #[cfg(feature = "storage")]
    async fn handle_import_volume(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::ImportVolumeResult;
        let availability_zone = params
            .get("AvailabilityZone")
            .cloned()
            .unwrap_or_else(|| "us-east-1a".to_string());
        let image_format = params
            .get("Image.Format")
            .cloned()
            .unwrap_or_else(|| "VMDK".to_string());
        let image_size = params
            .get("Image.Bytes")
            .and_then(|s| s.parse::<i64>().ok())
            .unwrap_or(0);
        let image_manifest = params
            .get("Image.ImportManifestUrl")
            .cloned()
            .unwrap_or_default();
        let volume_size = params
            .get("Volume.Size")
            .and_then(|s| s.parse::<i64>().ok())
            .unwrap_or(8);
        let description = params.get("Description").cloned();
        let mut st = state.write().await;
        let task = st
            .import_volume(
                availability_zone,
                image_format,
                image_size,
                image_manifest,
                volume_size,
                description,
            )
            .clone();
        wire::serialize_import_volume_response(&ImportVolumeResult {
            conversion_task: Some(import_volume_task_to_conversion_task_model(&task)),
        })
    }

