    #[cfg(feature = "compute")]
    async fn handle_request_spot_instances(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
    ) -> MockResponse {
        let spot_price = params
            .get("SpotPrice")
            .cloned()
            .unwrap_or_else(|| "0.05".to_string());
        let count = params
            .get("InstanceCount")
            .and_then(|s| s.parse().ok())
            .unwrap_or(1i32);
        let image_id = params
            .get("LaunchSpecification.ImageId")
            .cloned()
            .unwrap_or_default();
        let instance_type = params
            .get("LaunchSpecification.InstanceType")
            .cloned()
            .unwrap_or_else(|| "t2.micro".to_string());
        let mut st = state.write().await;
        let request_ids =
            st.request_spot_instances(&spot_price, count, &image_id, &instance_type, account_id);
        use crate::model::{
            RequestSpotInstancesResult, SpotInstanceRequest as ModelSpotRequest,
            SpotInstanceRequestList, SpotInstanceStatus,
        };
        let spot_items: Vec<ModelSpotRequest> = request_ids
            .iter()
            .map(|id| ModelSpotRequest {
                spot_instance_request_id: Some(id.clone()),
                state: Some("active".to_string()),
                status: Some(SpotInstanceStatus {
                    code: Some("fulfilled".to_string()),
                    ..Default::default()
                }),
                ..Default::default()
            })
            .collect();
        wire::serialize_request_spot_instances_response(&RequestSpotInstancesResult {
            spot_instance_requests: Some(SpotInstanceRequestList { items: spot_items }),
        })
    }

