    // Instance bundling is a legacy feature; bundle task state is not modelled.
    #[cfg(feature = "compute")]
    async fn handle_bundle_tasks_noop(
        &self,
        response_name: &str,
        set_element: &str,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            BundleInstanceResult, BundleTaskList, CancelBundleTaskResult, DescribeBundleTasksResult,
        };
        let _ = set_element;
        let st = self.state.get(DEFAULT_ACCOUNT_ID, "us-east-1");

        match response_name {
            "BundleInstanceResponse" => {
                let instance_id = params.get("InstanceId").cloned().unwrap_or_default();
                let bucket = params.get("Storage.S3.Bucket").cloned().unwrap_or_default();
                let prefix = params.get("Storage.S3.Prefix").cloned().unwrap_or_default();
                let mut guard = st.write().await;
                let task = guard.bundle_instance(instance_id, bucket, prefix).clone();
                wire::serialize_bundle_instance_response(&BundleInstanceResult {
                    bundle_task: Some(bundle_task_to_model(&task)),
                })
            }
            "CancelBundleTaskResponse" => {
                let bundle_id = match params.get("BundleId") {
                    Some(v) => v.clone(),
                    None => {
                        return MockResponse::error(400, "MissingParameter", "Missing 'BundleId'");
                    }
                };
                let mut guard = st.write().await;
                match guard.cancel_bundle_task(&bundle_id) {
                    Ok(task) => {
                        let model = bundle_task_to_model(task);
                        wire::serialize_cancel_bundle_task_response(&CancelBundleTaskResult {
                            bundle_task: Some(model),
                        })
                    }
                    Err(e) => ec2_error_response(&e),
                }
            }
            "DescribeBundleTasksResponse" => {
                let ids = parse_member_list(params, "BundleId");
                let guard = st.read().await;
                let items: Vec<crate::model::BundleTask> = guard
                    .describe_bundle_tasks(&ids)
                    .iter()
                    .map(bundle_task_to_model)
                    .collect();
                wire::serialize_describe_bundle_tasks_response(&DescribeBundleTasksResult {
                    bundle_tasks: Some(BundleTaskList { items }),
                })
            }
            _ => MockResponse::xml(200, String::new()),
        }
    }

