    #[cfg(feature = "advanced-network")]
    async fn handle_create_transit_gateway(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let description = params.get("Description").cloned().unwrap_or_default();
        let amazon_side_asn = params
            .get("Options.AmazonSideAsn")
            .and_then(|s| s.parse().ok())
            .unwrap_or(64512i64);
        let dns_support = params
            .get("Options.DnsSupport")
            .cloned()
            .unwrap_or_else(|| "enable".to_string());
        let vpn_ecmp = params
            .get("Options.VpnEcmpSupport")
            .cloned()
            .unwrap_or_else(|| "enable".to_string());
        let tags = parse_tag_specifications(params, "transit-gateway");
        let mut st = state.write().await;
        use crate::model::{
            CreateTransitGatewayResult, TransitGateway as ModelTgw, TransitGatewayOptions,
        };
        let tgw =
            st.create_transit_gateway(&description, amazon_side_asn, &dns_support, &vpn_ecmp, tags);
        wire::serialize_create_transit_gateway_response(&CreateTransitGatewayResult {
            transit_gateway: Some(ModelTgw {
                transit_gateway_id: Some(tgw.transit_gateway_id.clone()),
                state: Some("available".to_string()),
                description: Some(description.clone()),
                options: Some(TransitGatewayOptions {
                    amazon_side_asn: Some(amazon_side_asn),
                    ..Default::default()
                }),
                ..Default::default()
            }),
        })
    }

