    #[cfg(feature = "advanced-network")]
    async fn handle_modify_transit_gateway(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            ModifyTransitGatewayResult, TransitGateway as ModelTgw, TransitGatewayOptions,
        };
        let tgw_id = match params.get("TransitGatewayId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'TransitGatewayId'");
            }
        };
        let mut st = state.write().await;
        match st.transit_gateways.get_mut(&tgw_id) {
            Some(tgw) => {
                if let Some(desc) = params.get("Description") {
                    tgw.description = desc.clone();
                }
                if let Some(dns) = params.get("Options.DnsSupport") {
                    tgw.dns_support = dns.clone();
                }
                if let Some(ecmp) = params.get("Options.VpnEcmpSupport") {
                    tgw.vpn_ecmp_support = ecmp.clone();
                }
                wire::serialize_modify_transit_gateway_response(&ModifyTransitGatewayResult {
                    transit_gateway: Some(ModelTgw {
                        transit_gateway_id: Some(tgw.transit_gateway_id.clone()),
                        state: Some(tgw.state.clone()),
                        description: Some(tgw.description.clone()),
                        options: Some(TransitGatewayOptions {
                            amazon_side_asn: Some(tgw.amazon_side_asn),
                            ..Default::default()
                        }),
                        ..Default::default()
                    }),
                })
            }
            None => ec2_error_response(&Ec2Error::TransitGatewayNotFound(tgw_id)),
        }
    }

    #[cfg(feature = "advanced-network")]
    async fn handle_describe_transit_gateway_attachments_stateful(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            DescribeTransitGatewayAttachmentsResult, TransitGatewayAttachment as ModelTgwAtt,
            TransitGatewayAttachmentList,
        };
        let st = state.read().await;
        let ids = parse_member_list(params, "TransitGatewayAttachmentIds");
        let id_filter = |aid: &str| ids.is_empty() || ids.iter().any(|i| i == aid);
        let mut att_items: Vec<ModelTgwAtt> = Vec::new();
        for att in st.tgw_vpc_attachments.values() {
            if !id_filter(&att.attachment_id) {
                continue;
            }
            att_items.push(ModelTgwAtt {
                transit_gateway_attachment_id: Some(att.attachment_id.clone()),
                transit_gateway_id: Some(att.transit_gateway_id.clone()),
                resource_type: Some("vpc".to_string()),
                resource_id: Some(att.vpc_id.clone()),
                state: Some(att.state.clone()),
                ..Default::default()
            });
        }
        for att in st.tgw_peering_attachments.values() {
            if !id_filter(&att.attachment_id) {
                continue;
            }
            att_items.push(ModelTgwAtt {
                transit_gateway_attachment_id: Some(att.attachment_id.clone()),
                transit_gateway_id: Some(att.transit_gateway_id.clone()),
                resource_type: Some("peering".to_string()),
                state: Some(att.state.clone()),
                ..Default::default()
            });
        }
        for c in st.tgw_connects.values() {
            if !id_filter(&c.transit_gateway_attachment_id) {
                continue;
            }
            att_items.push(ModelTgwAtt {
                transit_gateway_attachment_id: Some(c.transit_gateway_attachment_id.clone()),
                transit_gateway_id: Some(c.transit_gateway_id.clone()),
                resource_type: Some("connect".to_string()),
                resource_id: Some(c.transport_transit_gateway_attachment_id.clone()),
                state: Some(c.state.clone()),
                ..Default::default()
            });
        }
        wire::serialize_describe_transit_gateway_attachments_response(
            &DescribeTransitGatewayAttachmentsResult {
                transit_gateway_attachments: Some(TransitGatewayAttachmentList {
                    items: att_items,
                }),
                ..Default::default()
            },
        )
    }

