    #[cfg(feature = "advanced-network")]
    async fn handle_modify_tgw_vpc_attachment(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            ModifyTransitGatewayVpcAttachmentResult, TransitGatewayVpcAttachment as ModelTgwVpcAtt,
        };
        let att_id = match params.get("TransitGatewayAttachmentId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'TransitGatewayAttachmentId'",
                );
            }
        };
        let mut st = state.write().await;
        match st.tgw_vpc_attachments.get_mut(&att_id) {
            Some(att) => {
                let add_subnets = parse_member_list(params, "AddSubnetIds");
                let remove_subnets = parse_member_list(params, "RemoveSubnetIds");
                for s in &add_subnets {
                    if !att.subnet_ids.contains(s) {
                        att.subnet_ids.push(s.clone());
                    }
                }
                att.subnet_ids.retain(|s| !remove_subnets.contains(s));
                wire::serialize_modify_transit_gateway_vpc_attachment_response(
                    &ModifyTransitGatewayVpcAttachmentResult {
                        transit_gateway_vpc_attachment: Some(ModelTgwVpcAtt {
                            transit_gateway_attachment_id: Some(att.attachment_id.clone()),
                            transit_gateway_id: Some(att.transit_gateway_id.clone()),
                            vpc_id: Some(att.vpc_id.clone()),
                            state: Some(att.state.clone()),
                            ..Default::default()
                        }),
                    },
                )
            }
            None => ec2_error_response(&Ec2Error::TgwVpcAttachmentNotFound(att_id)),
        }
    }

