    #[cfg(feature = "advanced-network")]
    async fn handle_search_tgw_routes(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            SearchTransitGatewayRoutesResult, TransitGatewayRoute, TransitGatewayRouteList,
        };
        let rtb_id = params
            .get("TransitGatewayRouteTableId")
            .cloned()
            .unwrap_or_default();
        let st = state.read().await;
        let route_items: Vec<TransitGatewayRoute> = st
            .tgw_routes
            .get(&rtb_id)
            .map(|routes| {
                routes
                    .iter()
                    .map(|r| TransitGatewayRoute {
                        destination_cidr_block: Some(r.destination_cidr_block.clone()),
                        state: Some(r.state.clone()),
                        r#type: Some(r.route_type.clone()),
                        ..Default::default()
                    })
                    .collect()
            })
            .unwrap_or_default();
        wire::serialize_search_transit_gateway_routes_response(&SearchTransitGatewayRoutesResult {
            routes: Some(TransitGatewayRouteList { items: route_items }),
            ..Default::default()
        })
    }

    // TGW route table association/propagation operations are accepted; state
    // always returns "associated" since fine-grained association tracking is not
    // modelled.
    #[cfg(feature = "advanced-network")]
    async fn handle_tgw_noop(&self, response_name: &str, element_name: &str) -> MockResponse {
        let xml = format!(
            r#"<?xml version="1.0"?><{response_name} xmlns="http://ec2.amazonaws.com/doc/2016-11-15/"><requestId>{}</requestId><{element_name}><state>associated</state></{element_name}></{response_name}>"#,
            uuid::Uuid::new_v4()
        );
        MockResponse::xml(200, xml)
    }

    // TGW route table association/propagation listing is not individually
    // tracked; always returns empty.
    #[cfg(feature = "advanced-network")]
    async fn handle_tgw_empty_set(&self, response_name: &str, set_element: &str) -> MockResponse {
        use crate::model::{
            GetTransitGatewayRouteTableAssociationsResult,
            GetTransitGatewayRouteTablePropagationsResult,
        };

        match response_name {
            "GetTransitGatewayRouteTableAssociationsResponse" => {
                let _ = set_element;
                wire::serialize_get_transit_gateway_route_table_associations_response(
                    &GetTransitGatewayRouteTableAssociationsResult::default(),
                )
            }
            "GetTransitGatewayRouteTablePropagationsResponse" => {
                let _ = set_element;
                wire::serialize_get_transit_gateway_route_table_propagations_response(
                    &GetTransitGatewayRouteTablePropagationsResult::default(),
                )
            }
            _ => MockResponse::xml(200, String::new()),
        }
    }

