    #[cfg(feature = "advanced-network")]
    async fn handle_create_tgw_multicast_domain(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
        region: &str,
    ) -> MockResponse {
        let tgw_id = match params.get("TransitGatewayId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'TransitGatewayId'");
            }
        };
        let igmpv2 = params
            .get("Options.Igmpv2Support")
            .cloned()
            .unwrap_or_else(|| "disable".to_string());
        let static_sources = params
            .get("Options.StaticSourcesSupport")
            .cloned()
            .unwrap_or_else(|| "disable".to_string());
        let auto_accept = params
            .get("Options.AutoAcceptSharedAssociations")
            .cloned()
            .unwrap_or_else(|| "disable".to_string());
        let tags = parse_tag_specifications(params, "transit-gateway-multicast-domain");
        let mut st = state.write().await;
        match st.create_tgw_multicast_domain(
            &tgw_id,
            &igmpv2,
            &static_sources,
            &auto_accept,
            account_id,
            region,
            tags,
        ) {
            Ok(d) => {
                use crate::model::{
                    CreateTransitGatewayMulticastDomainResult, TransitGatewayMulticastDomain,
                    TransitGatewayMulticastDomainOptions,
                };
                let resp = CreateTransitGatewayMulticastDomainResult {
                    transit_gateway_multicast_domain: Some(TransitGatewayMulticastDomain {
                        transit_gateway_multicast_domain_id: Some(
                            d.transit_gateway_multicast_domain_id.clone(),
                        ),
                        transit_gateway_id: Some(d.transit_gateway_id.clone()),
                        transit_gateway_multicast_domain_arn: Some(
                            d.transit_gateway_multicast_domain_arn.clone(),
                        ),
                        owner_id: Some(d.owner_id.clone()),
                        state: Some(d.state.clone()),
                        creation_time: Some(d.creation_time.clone()),
                        options: Some(TransitGatewayMulticastDomainOptions {
                            igmpv2_support: Some(d.igmpv2_support.clone()),
                            static_sources_support: Some(d.static_sources_support.clone()),
                            auto_accept_shared_associations: Some(
                                d.auto_accept_shared_associations.clone(),
                            ),
                        }),
                        ..Default::default()
                    }),
                };
                wire::serialize_create_transit_gateway_multicast_domain_response(&resp)
            }
            Err(e) => ec2_error_response(&e),
        }
    }

