    // --- Dedicated Host handlers ---

    #[cfg(feature = "compute")]
    async fn handle_allocate_hosts(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{AllocateHostsResult, ResponseHostIdList};
        let availability_zone = params
            .get("AvailabilityZone")
            .cloned()
            .unwrap_or_else(|| "us-east-1a".to_string());
        let instance_type = params.get("InstanceType").cloned();
        let quantity: usize = params
            .get("Quantity")
            .and_then(|v| v.parse().ok())
            .unwrap_or(1);
        let auto_placement = params
            .get("AutoPlacement")
            .cloned()
            .unwrap_or_else(|| "on".to_string());
        let host_recovery = params
            .get("HostRecovery")
            .cloned()
            .unwrap_or_else(|| "off".to_string());
        let tags = parse_tag_specifications(params, "dedicated-host");
        let mut st = state.write().await;
        let host_ids = st.allocate_hosts(
            &availability_zone,
            instance_type,
            quantity,
            &auto_placement,
            &host_recovery,
            tags,
        );
        wire::serialize_allocate_hosts_response(&AllocateHostsResult {
            host_ids: Some(ResponseHostIdList { items: host_ids }),
        })
    }

    #[cfg(feature = "compute")]
    async fn handle_describe_hosts(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{DescribeHostsResult, Host, HostList};
        let st = state.read().await;
        let host_id_params = parse_member_list(params, "HostId");
        let hosts: Vec<Host> = st
            .dedicated_hosts
            .values()
            .filter(|h| {
                if !host_id_params.is_empty() && !host_id_params.contains(&h.host_id) {
                    return false;
                }
                true
            })
            .map(|h| Host {
                host_id: Some(h.host_id.clone()),
                availability_zone: Some(h.availability_zone.clone()),
                auto_placement: Some(h.auto_placement.clone()),
                host_recovery: Some(h.host_recovery.clone()),
                state: Some(h.state.clone()),
                tags: if h.tags.is_empty() {
                    None
                } else {
                    Some(tags_to_model(&h.tags))
                },
                ..Default::default()
            })
            .collect();
        wire::serialize_describe_hosts_response(&DescribeHostsResult {
            hosts: Some(HostList { items: hosts }),
            next_token: None,
        })
    }

