    // --- VPC Endpoint Service Configuration handlers ---

    #[cfg(feature = "network")]
    async fn handle_create_vpc_endpoint_service_configuration(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            CreateVpcEndpointServiceConfigurationResult, ServiceConfiguration, ServiceTypeDetail,
            ServiceTypeDetailSet,
        };
        let acceptance_required = params
            .get("AcceptanceRequired")
            .map(|v| v == "true")
            .unwrap_or(false);
        let mut nlb_arns = Vec::new();
        let mut i = 1;
        loop {
            let key = format!("NetworkLoadBalancerArn.{i}");
            match params.get(&key) {
                Some(v) => {
                    nlb_arns.push(v.clone());
                    i += 1;
                }
                None => break,
            }
        }
        let mut glb_arns = Vec::new();
        let mut i = 1;
        loop {
            let key = format!("GatewayLoadBalancerArn.{i}");
            match params.get(&key) {
                Some(v) => {
                    glb_arns.push(v.clone());
                    i += 1;
                }
                None => break,
            }
        }
        let tags = parse_tag_specifications(params, "vpc-endpoint-service");
        let mut st = state.write().await;
        let cfg = st.create_vpc_endpoint_service_configuration(
            acceptance_required,
            nlb_arns,
            glb_arns,
            tags,
        );
        let svc_type_str = cfg.service_type.clone();
        let svc_id = cfg.service_id.clone();
        let svc_name = cfg.service_name.clone();
        let acceptance = cfg.acceptance_required;
        let svc_state = cfg.state.clone();
        let svc_tags = cfg.tags.clone();
        drop(st);
        wire::serialize_create_vpc_endpoint_service_configuration_response(
            &CreateVpcEndpointServiceConfigurationResult {
                service_configuration: Some(ServiceConfiguration {
                    service_id: Some(svc_id),
                    service_name: Some(svc_name),
                    acceptance_required: Some(acceptance),
                    service_state: Some(svc_state),
                    service_type: Some(ServiceTypeDetailSet {
                        items: vec![ServiceTypeDetail {
                            service_type: Some(svc_type_str),
                        }],
                    }),
                    tags: if svc_tags.is_empty() {
                        None
                    } else {
                        Some(tags_to_model(&svc_tags))
                    },
                    ..Default::default()
                }),
                ..Default::default()
            },
        )
    }

