    #[cfg(feature = "network")]
    async fn handle_create_vpc_block_public_access_exclusion(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let mode = match params.get("InternetGatewayExclusionMode") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'InternetGatewayExclusionMode'",
                );
            }
        };
        // The AWS API accepts either VpcId or SubnetId; we record an ARN
        // synthesised from whichever was provided.
        let resource_arn = if let Some(vpc_id) = params.get("VpcId") {
            format!("arn:aws:ec2:us-east-1:000000000000:vpc/{vpc_id}")
        } else if let Some(subnet_id) = params.get("SubnetId") {
            format!("arn:aws:ec2:us-east-1:000000000000:subnet/{subnet_id}")
        } else {
            return MockResponse::error(
                400,
                "MissingParameter",
                "One of 'VpcId' or 'SubnetId' is required",
            );
        };
        let tags = parse_tag_specifications(params, "vpc-block-public-access-exclusion");
        let mut st = state.write().await;
        let ex = st.create_vpc_block_public_access_exclusion(&resource_arn, &mode, tags);
        use crate::model::CreateVpcBlockPublicAccessExclusionResult;
        wire::serialize_create_vpc_block_public_access_exclusion_response(
            &CreateVpcBlockPublicAccessExclusionResult {
                vpc_block_public_access_exclusion: Some(vpc_bpa_exclusion_to_model(ex)),
            },
        )
    }

