    #[cfg(feature = "network")]
    async fn handle_reset_network_interface_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let eni_id = match params.get("NetworkInterfaceId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'NetworkInterfaceId'",
                );
            }
        };
        // The legacy ResetNetworkInterfaceAttribute query carries the
        // attribute name in the `SourceDestCheck` parameter (modelled as a
        // string in Smithy); some callers also send `Attribute`. AWS only
        // supports `sourceDestCheck` and `attachment`; the latter cannot
        // actually be reset and the API returns InvalidParameterValue.
        let attribute = match params
            .get("SourceDestCheck")
            .or_else(|| params.get("Attribute"))
        {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'SourceDestCheck'");
            }
        };
        match attribute.as_str() {
            "sourceDestCheck" => {
                let mut st = state.write().await;
                match st.network_interfaces.get_mut(&eni_id) {
                    Some(eni) => {
                        eni.source_dest_check = true;
                        wire::serialize_reset_network_interface_attribute_response()
                    }
                    None => ec2_error_response(&Ec2Error::NetworkInterfaceNotFound(eni_id)),
                }
            }
            "attachment" => ec2_error_response(&Ec2Error::InvalidParameterValue(format!(
                "Network interface attribute '{attribute}' cannot be reset"
            ))),
            other => ec2_error_response(&Ec2Error::InvalidParameterValue(format!(
                "Invalid network interface attribute: {other}"
            ))),
        }
    }

