    // --- Capacity Reservation Fleets ---

    #[cfg(feature = "compute")]
    async fn handle_create_capacity_reservation_fleet(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
        region: &str,
    ) -> MockResponse {
        let total_target_capacity = match params
            .get("TotalTargetCapacity")
            .and_then(|s| s.parse::<i32>().ok())
        {
            Some(v) => v,
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'TotalTargetCapacity'",
                );
            }
        };
        let allocation_strategy = params.get("AllocationStrategy").cloned();
        let tenancy = params.get("Tenancy").cloned();
        let instance_match_criteria = params.get("InstanceMatchCriteria").cloned();
        let end_date = params.get("EndDate").cloned();
        // Parse repeated InstanceTypeSpecification.{N}.{Field}
        let mut specs: Vec<crate::types::CapacityReservationFleetInstanceSpec> = Vec::new();
        let mut i = 1;
        loop {
            let it_key = format!("InstanceTypeSpecification.{i}.InstanceType");
            let ip_key = format!("InstanceTypeSpecification.{i}.InstancePlatform");
            let it = params.get(&it_key).cloned();
            let ip = params.get(&ip_key).cloned();
            if it.is_none() && ip.is_none() {
                break;
            }
            let instance_type = it.unwrap_or_default();
            let instance_platform = ip.unwrap_or_else(|| "Linux/UNIX".to_string());
            let availability_zone = params
                .get(&format!("InstanceTypeSpecification.{i}.AvailabilityZone"))
                .cloned();
            let ebs_optimized = params
                .get(&format!("InstanceTypeSpecification.{i}.EbsOptimized"))
                .map(|v| v == "true");
            let priority = params
                .get(&format!("InstanceTypeSpecification.{i}.Priority"))
                .and_then(|s| s.parse::<i32>().ok());
            let weight = params
                .get(&format!("InstanceTypeSpecification.{i}.Weight"))
                .and_then(|s| s.parse::<f64>().ok());
            specs.push(crate::types::CapacityReservationFleetInstanceSpec {
                instance_type,
                instance_platform,
                availability_zone,
                ebs_optimized,
                priority,
                weight,
            });
            i += 1;
        }
        let tags = parse_tag_specifications(params, "capacity-reservation-fleet");
        let mut st = state.write().await;
        match st.create_capacity_reservation_fleet(
            allocation_strategy,
            tenancy,
            instance_match_criteria,
            total_target_capacity,
            end_date,
            specs,
            account_id,
            region,
            tags,
        ) {
            Ok(fleet) => {
                use crate::model::{
                    CreateCapacityReservationFleetResult, FleetCapacityReservation,
                    FleetCapacityReservationSet,
                };
                let items: Vec<FleetCapacityReservation> = fleet
                    .instance_type_specifications
                    .iter()
                    .map(|s| FleetCapacityReservation {
                        availability_zone: s.availability_zone.clone(),
                        instance_type: Some(s.instance_type.clone()),
                        instance_platform: Some(s.instance_platform.clone()),
                        ebs_optimized: s.ebs_optimized,
                        priority: s.priority,
                        weight: s.weight,
                        fulfilled_capacity: Some(s.weight.unwrap_or(1.0)),
                        total_instance_count: Some(1),
                        create_date: Some(fleet.create_time.clone()),
                        ..Default::default()
                    })
                    .collect();
                wire::serialize_create_capacity_reservation_fleet_response(
                    &CreateCapacityReservationFleetResult {
                        capacity_reservation_fleet_id: Some(
                            fleet.capacity_reservation_fleet_id.clone(),
                        ),
                        state: Some(fleet.state.clone()),
                        total_target_capacity: Some(fleet.total_target_capacity),
                        total_fulfilled_capacity: Some(fleet.total_fulfilled_capacity),
                        instance_match_criteria: Some(fleet.instance_match_criteria.clone()),
                        allocation_strategy: Some(fleet.allocation_strategy.clone()),
                        tenancy: Some(fleet.tenancy.clone()),
                        end_date: fleet.end_date.clone(),
                        create_time: Some(fleet.create_time.clone()),
                        fleet_capacity_reservations: Some(FleetCapacityReservationSet { items }),
                        tags: Some(tags_to_model(&fleet.tags)),
                    },
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

