    #[cfg(feature = "compute")]
    async fn handle_cancel_capacity_reservation_fleets(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            CancelCapacityReservationFleetError, CancelCapacityReservationFleetsResult,
            CapacityReservationFleetCancellationState,
            CapacityReservationFleetCancellationStateSet,
            FailedCapacityReservationFleetCancellationResult,
            FailedCapacityReservationFleetCancellationResultSet,
        };
        let ids = parse_member_list(params, "CapacityReservationFleetId");
        if ids.is_empty() {
            return MockResponse::error(
                400,
                "MissingParameter",
                "Missing 'CapacityReservationFleetId'",
            );
        }
        let mut st = state.write().await;
        let mut successes: Vec<CapacityReservationFleetCancellationState> = Vec::new();
        let mut failures: Vec<FailedCapacityReservationFleetCancellationResult> = Vec::new();
        for id in ids {
            match st.cancel_capacity_reservation_fleet(&id) {
                Ok(()) => {
                    successes.push(CapacityReservationFleetCancellationState {
                        capacity_reservation_fleet_id: Some(id),
                        current_fleet_state: Some("cancelled".to_string()),
                        previous_fleet_state: Some("active".to_string()),
                    });
                }
                Err(_) => {
                    failures.push(FailedCapacityReservationFleetCancellationResult {
                        capacity_reservation_fleet_id: Some(id.clone()),
                        cancel_capacity_reservation_fleet_error: Some(
                            CancelCapacityReservationFleetError {
                                code: Some(
                                    "InvalidCapacityReservationFleetId.NotFound".to_string(),
                                ),
                                message: Some(format!(
                                    "The capacity reservation fleet '{id}' does not exist"
                                )),
                            },
                        ),
                    });
                }
            }
        }
        wire::serialize_cancel_capacity_reservation_fleets_response(
            &CancelCapacityReservationFleetsResult {
                successful_fleet_cancellations: Some(
                    CapacityReservationFleetCancellationStateSet { items: successes },
                ),
                failed_fleet_cancellations: Some(
                    FailedCapacityReservationFleetCancellationResultSet { items: failures },
                ),
            },
        )
    }

