    #[cfg(feature = "compute")]
    async fn handle_update_interruptible_capacity_reservation_allocation(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let cr_id = match params.get("CapacityReservationId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'CapacityReservationId'",
                );
            }
        };
        // The spec passes CapacityReservationId here, but our state keys
        // allocations by their own allocation ID. Resolve by scanning for
        // an allocation that references this reservation.
        let allocation_id = {
            let st = state.read().await;
            st.interruptible_capacity_reservation_allocations
                .values()
                .find(|a| a.capacity_reservation_id == cr_id)
                .map(|a| a.allocation_id.clone())
        };
        let allocation_id = match allocation_id {
            Some(id) => id,
            None => {
                return ec2_error_response(
                    &Ec2Error::InvalidInterruptibleCapacityReservationAllocationNotFound(
                        cr_id.clone(),
                    ),
                );
            }
        };
        let instance_count = params
            .get("TargetInstanceCount")
            .or_else(|| params.get("InstanceCount"))
            .and_then(|s| s.parse::<i32>().ok());
        let start = params.get("StartDateTime").cloned();
        let end = params.get("EndDateTime").cloned();
        let allocation_type = params.get("AllocationType").cloned();
        let mut st = state.write().await;
        match st.update_interruptible_capacity_reservation_allocation(
            &allocation_id,
            instance_count,
            start,
            end,
            allocation_type,
        ) {
            Ok(alloc) => {
                use crate::model::UpdateInterruptibleCapacityReservationAllocationResult;
                wire::serialize_update_interruptible_capacity_reservation_allocation_response(
                    &UpdateInterruptibleCapacityReservationAllocationResult {
                        instance_count: Some(alloc.instance_count),
                        interruptible_capacity_reservation_id: Some(alloc.allocation_id.clone()),
                        interruption_type: Some(alloc.allocation_type.clone()),
                        source_capacity_reservation_id: Some(alloc.capacity_reservation_id.clone()),
                        status: Some(alloc.state.clone()),
                        target_instance_count: Some(alloc.instance_count),
                    },
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

