    // --- Id format (no real per-resource id-length tracking; report long ids globally). ---

    #[cfg(feature = "extras")]
    async fn handle_describe_id_format(&self, params: &HashMap<String, String>) -> MockResponse {
        use crate::model::{IdFormat, IdFormatList};
        let st = self.state.get(DEFAULT_ACCOUNT_ID, "us-east-1");
        let st = st.read().await;
        let resource_filter = params.get("Resource").cloned();
        // Long IDs have been the AWS default since 2018; report `true` for
        // any resource type, including ones we have not explicitly tracked.
        let known_resources = [
            "instance",
            "reservation",
            "snapshot",
            "volume",
            "vpc",
            "subnet",
            "internet-gateway",
            "security-group",
            "image",
            "network-interface",
            "route-table",
        ];
        let resources: Vec<&str> = if let Some(ref r) = resource_filter {
            vec![r.as_str()]
        } else {
            known_resources.to_vec()
        };
        let items: Vec<IdFormat> = resources
            .into_iter()
            .map(|r| {
                let entry = st.id_format.get(r);
                IdFormat {
                    deadline: entry.and_then(|e| e.deadline.clone()),
                    resource: Some(r.to_string()),
                    use_long_ids: Some(entry.map(|e| e.use_long_ids).unwrap_or(true)),
                }
            })
            .collect();
        wire::serialize_describe_id_format_response(&DescribeIdFormatResult {
            statuses: Some(IdFormatList { items }),
        })
    }

    #[cfg(feature = "extras")]
    async fn handle_describe_identity_id_format(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
    ) -> MockResponse {
        use crate::model::{IdFormat, IdFormatList};
        let st = state.read().await;
        let mut items: Vec<IdFormat> = st
            .id_format
            .iter()
            .map(|(resource, entry)| IdFormat {
                resource: Some(resource.clone()),
                use_long_ids: Some(entry.use_long_ids),
                deadline: entry.deadline.clone(),
            })
            .collect();
        if items.is_empty() {
            for resource in &["instance", "reservation", "snapshot", "volume", "image"] {
                items.push(IdFormat {
                    resource: Some((*resource).to_string()),
                    use_long_ids: Some(true),
                    deadline: None,
                });
            }
        }
        wire::serialize_describe_identity_id_format_response(&DescribeIdentityIdFormatResult {
            statuses: Some(IdFormatList { items }),
        })
    }

