    #[cfg(feature = "network")]
    async fn handle_describe_network_interface_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            AttributeBooleanValue, AttributeValue, GroupIdentifier, GroupIdentifierList,
            NetworkInterfaceAttachment,
        };
        let eni_id = match params.get("NetworkInterfaceId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'NetworkInterfaceId'",
                );
            }
        };
        let attribute = params.get("Attribute").cloned().unwrap_or_default();
        let st = state.read().await;
        let eni = match st.network_interfaces.get(&eni_id) {
            Some(e) => e,
            None => {
                return ec2_error_response(&Ec2Error::NetworkInterfaceNotFound(eni_id));
            }
        };
        let mut result = DescribeNetworkInterfaceAttributeResult {
            network_interface_id: Some(eni.network_interface_id.clone()),
            ..Default::default()
        };
        match attribute.as_str() {
            "description" => {
                result.description = Some(AttributeValue {
                    value: Some(eni.description.clone()),
                });
            }
            "groupSet" => {
                result.groups = Some(GroupIdentifierList {
                    items: eni
                        .security_groups
                        .iter()
                        .map(|g| GroupIdentifier {
                            group_id: Some(g.clone()),
                            group_name: None,
                        })
                        .collect(),
                });
            }
            "sourceDestCheck" => {
                result.source_dest_check = Some(AttributeBooleanValue {
                    value: Some(eni.source_dest_check),
                });
            }
            "attachment" => {
                if let Some(aid) = eni.attachment_id.as_ref() {
                    result.attachment = Some(NetworkInterfaceAttachment {
                        attachment_id: Some(aid.clone()),
                        instance_id: eni.instance_id.clone(),
                        device_index: eni.device_index,
                        status: Some("attached".to_string()),
                        ..Default::default()
                    });
                }
            }
            "associatePublicIpAddress" => {
                result.associate_public_ip_address = Some(false);
            }
            _ => {}
        }
        wire::serialize_describe_network_interface_attribute_response(&result)
    }

