    #[cfg(feature = "compute")]
    async fn handle_describe_image_references(
        &self,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{ImageReference, ImageReferenceList};
        let st = self.state.get(DEFAULT_ACCOUNT_ID, "us-east-1");
        let st = st.read().await;
        let image_ids = parse_member_list(params, "ImageId");
        // Walk instances, emitting a reference for each instance that boots
        // from one of the requested images.
        let items: Vec<ImageReference> = st
            .instances
            .values()
            .filter(|inst| image_ids.is_empty() || image_ids.contains(&inst.image_id))
            .map(|inst| ImageReference {
                arn: Some(format!(
                    "arn:aws:ec2:us-east-1:{}:instance/{}",
                    inst.owner_id, inst.instance_id
                )),
                image_id: Some(inst.image_id.clone()),
                resource_type: Some("instance".to_string()),
            })
            .collect();
        wire::serialize_describe_image_references_response(&DescribeImageReferencesResult {
            image_references: Some(ImageReferenceList { items }),
            next_token: None,
        })
    }

