    #[cfg(feature = "extras")]
    async fn handle_describe_traffic_mirror_filter_rules(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::TrafficMirrorFilterRuleSet;
        let rule_ids = parse_member_list(params, "TrafficMirrorFilterRuleId");
        let filter_id = params.get("TrafficMirrorFilterId").cloned();
        let st = state.read().await;
        let mut items: Vec<crate::model::TrafficMirrorFilterRule> = Vec::new();
        for filter in st.traffic_mirror_filters.values() {
            if let Some(ref fid) = filter_id {
                if &filter.traffic_mirror_filter_id != fid {
                    continue;
                }
            }
            for rule in filter
                .ingress_filter_rules
                .iter()
                .chain(filter.egress_filter_rules.iter())
            {
                if !rule_ids.is_empty() && !rule_ids.contains(&rule.traffic_mirror_filter_rule_id) {
                    continue;
                }
                items.push(traffic_mirror_filter_rule_to_model(rule));
            }
        }
        wire::serialize_describe_traffic_mirror_filter_rules_response(
            &DescribeTrafficMirrorFilterRulesResult {
                traffic_mirror_filter_rules: Some(TrafficMirrorFilterRuleSet { items }),
                next_token: None,
            },
        )
    }

