    #[cfg(feature = "network")]
    async fn handle_describe_security_group_references(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{SecurityGroupReference, SecurityGroupReferences};
        let group_ids = parse_member_list(params, "GroupId");
        let st = state.read().await;
        // Walk SGs and any rules whose user-id-group-pair group ID belongs to a SG
        // in a different VPC: emit a cross-VPC reference. If a peering connection
        // exists between the two VPCs, surface it.
        let sg_by_id: HashMap<&String, &crate::types::SecurityGroup> =
            st.security_groups.iter().collect();
        let mut items: Vec<SecurityGroupReference> = Vec::new();
        for sg in st.security_groups.values() {
            if !group_ids.is_empty() && !group_ids.contains(&sg.group_id) {
                continue;
            }
            for rule in sg.ingress_rules.iter().chain(sg.egress_rules.iter()) {
                for pair in &rule.user_id_group_pairs {
                    if let Some(other_sg) = sg_by_id.get(&pair.group_id)
                        && other_sg.vpc_id != sg.vpc_id
                    {
                        let peering_id = st
                            .vpc_peering_connections
                            .values()
                            .find(|p| {
                                let acc = p.accepter_vpc_id.as_deref().unwrap_or("");
                                (p.requester_vpc_id == sg.vpc_id && acc == other_sg.vpc_id)
                                    || (p.requester_vpc_id == other_sg.vpc_id && acc == sg.vpc_id)
                            })
                            .map(|p| p.peering_id.clone());
                        items.push(SecurityGroupReference {
                            group_id: Some(sg.group_id.clone()),
                            referencing_vpc_id: Some(other_sg.vpc_id.clone()),
                            vpc_peering_connection_id: peering_id,
                            transit_gateway_id: None,
                        });
                    }
                }
            }
        }
        wire::serialize_describe_security_group_references_response(
            &DescribeSecurityGroupReferencesResult {
                security_group_reference_set: Some(SecurityGroupReferences { items }),
            },
        )
    }

