    #[cfg(feature = "extras")]
    async fn handle_describe_ipam_scopes(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{DescribeIpamScopesResult, IpamScopeSet};
        let st = state.read().await;
        let ids = parse_member_list(params, "IpamScopeId");
        let filters = parse_filters(params);
        let items: Vec<_> = st
            .ipam_scopes
            .values()
            .filter(|s| {
                if !ids.is_empty() && !ids.contains(&s.ipam_scope_id) {
                    return false;
                }
                apply_filters_to_tags(
                    &s.tags,
                    &filters,
                    &[
                        ("ipam-scope-id", Some(&s.ipam_scope_id)),
                        ("ipam-id", Some(&s.ipam_arn)),
                        (
                            "is-default",
                            Some(if s.is_default { "true" } else { "false" }),
                        ),
                    ],
                )
            })
            .map(ipam_scope_to_model)
            .collect();
        wire::serialize_describe_ipam_scopes_response(&DescribeIpamScopesResult {
            ipam_scopes: Some(IpamScopeSet { items }),
            ..Default::default()
        })
    }

