    #[cfg(feature = "compute")]
    async fn handle_get_capacity_reservation_usage(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::InstanceUsageSet;
        let cr_id = match params.get("CapacityReservationId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'CapacityReservationId'",
                );
            }
        };
        let st = state.read().await;
        let cr = match st.capacity_reservations.get(&cr_id) {
            Some(c) => c,
            None => {
                return ec2_error_response(&Ec2Error::CapacityReservationNotFound(cr_id.clone()));
            }
        };
        let mut by_account: HashMap<String, i32> = HashMap::new();
        for inst in st.instances.values() {
            if let Some(spec) = inst.capacity_reservation_specification.as_ref()
                && spec.capacity_reservation_id.as_deref() == Some(cr_id.as_str())
            {
                *by_account.entry(inst.owner_id.clone()).or_insert(0) += 1;
            }
        }
        let items: Vec<crate::model::InstanceUsage> = by_account
            .into_iter()
            .map(|(account, count)| crate::model::InstanceUsage {
                account_id: Some(account),
                used_instance_count: Some(count),
            })
            .collect();
        wire::serialize_get_capacity_reservation_usage_response(
            &GetCapacityReservationUsageResult {
                capacity_reservation_id: Some(cr_id),
                instance_type: Some(cr.instance_type.clone()),
                state: Some(cr.state.clone()),
                total_instance_count: Some(cr.total_instance_count),
                available_instance_count: Some(cr.available_instance_count),
                instance_usages: Some(InstanceUsageSet { items }),
                next_token: None,
                ..Default::default()
            },
        )
    }

