    #[cfg(feature = "advanced-network")]
    async fn handle_get_transit_gateway_multicast_domain_associations(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::TransitGatewayMulticastDomainAssociationList;
        let domain_id = match params.get("TransitGatewayMulticastDomainId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'TransitGatewayMulticastDomainId'",
                );
            }
        };
        let st = state.read().await;
        // The Get* result returns one association per (domain_id, attachment_id, subnet)
        // tuple, since the per-association model carries a single `subnet` rather than
        // a subnet list.
        let mut items: Vec<crate::model::TransitGatewayMulticastDomainAssociation> = Vec::new();
        for ((dom, _attach), assoc) in st.tgw_multicast_domain_associations.iter() {
            if dom != &domain_id {
                continue;
            }
            for sub in &assoc.subnets {
                items.push(tgw_multicast_domain_association_to_model_get(assoc, sub));
            }
            if assoc.subnets.is_empty() {
                items.push(tgw_multicast_domain_association_to_model_get_no_subnet(
                    assoc,
                ));
            }
        }
        wire::serialize_get_transit_gateway_multicast_domain_associations_response(
            &GetTransitGatewayMulticastDomainAssociationsResult {
                multicast_domain_associations: Some(TransitGatewayMulticastDomainAssociationList {
                    items,
                }),
                next_token: None,
            },
        )
    }

