    async fn handle_get_ipam_policy_allocation_rules(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            IpamPolicyAllocationRule as ModelIpamPolicyAllocationRule,
            IpamPolicyAllocationRuleList, IpamPolicyDocument, IpamPolicyDocumentSet,
        };
        let policy_id = match params.get("IpamPolicyId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'IpamPolicyId'");
            }
        };
        let st = state.read().await;
        let policy = match st.ipam_policies.get(&policy_id) {
            Some(p) => p,
            None => return ec2_error_response(&Ec2Error::InvalidIpamPolicyNotFound(policy_id)),
        };
        let rules: Vec<ModelIpamPolicyAllocationRule> = policy
            .allocation_rules
            .iter()
            .map(|r| ModelIpamPolicyAllocationRule {
                source_ipam_pool_id: r.source_ipam_pool_id.clone(),
            })
            .collect();
        let doc = IpamPolicyDocument {
            ipam_policy_id: Some(policy.ipam_policy_id.clone()),
            allocation_rules: Some(IpamPolicyAllocationRuleList { items: rules }),
            ..Default::default()
        };
        wire::serialize_get_ipam_policy_allocation_rules_response(
            &GetIpamPolicyAllocationRulesResult {
                ipam_policy_documents: Some(IpamPolicyDocumentSet { items: vec![doc] }),
                next_token: None,
            },
        )
    }

