    #[cfg(feature = "network")]
    async fn handle_get_associated_ipv6_pool_cidrs(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::Ipv6CidrAssociationSet;
        let pool_id = match params.get("PoolId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'PoolId'"),
        };
        let st = state.read().await;
        // Only emit CIDRs from pools whose address family is ipv6.
        let is_ipv6 = st
            .ipam_pools
            .get(&pool_id)
            .map(|p| p.address_family == "ipv6")
            .unwrap_or(false);
        let items: Vec<crate::model::Ipv6CidrAssociation> = if is_ipv6 {
            st.ipam_pool_cidrs
                .iter()
                .filter(|((pid, _), _)| pid == &pool_id)
                .map(|((_, cidr), _entry)| crate::model::Ipv6CidrAssociation {
                    ipv6_cidr: Some(cidr.clone()),
                    associated_resource: Some(pool_id.clone()),
                })
                .collect()
        } else {
            Vec::new()
        };
        wire::serialize_get_associated_ipv6_pool_cidrs_response(&GetAssociatedIpv6PoolCidrsResult {
            ipv6_cidr_associations: Some(Ipv6CidrAssociationSet { items }),
            next_token: None,
        })
    }

