    #[cfg(feature = "network")]
    async fn handle_get_ipam_address_history(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{IpamAddressHistoryRecord, IpamAddressHistoryRecordSet};
        let cidr = match params.get("Cidr") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'Cidr'"),
        };
        let st = state.read().await;
        // History is the allocation list filtered by the queried CIDR, ordered
        // by allocation_id (which is monotonically increasing and serves as a
        // proxy for (start, end)).
        let mut allocs: Vec<&crate::types::IpamPoolAllocation> = st
            .ipam_pool_allocations
            .values()
            .filter(|a| a.cidr == cidr)
            .collect();
        allocs.sort_by(|a, b| a.ipam_pool_allocation_id.cmp(&b.ipam_pool_allocation_id));
        let items: Vec<IpamAddressHistoryRecord> = allocs
            .into_iter()
            .map(|a| IpamAddressHistoryRecord {
                resource_cidr: Some(a.cidr.clone()),
                resource_id: a.resource_id.clone(),
                resource_type: Some(a.resource_type.clone()),
                resource_region: a.resource_region.clone(),
                resource_owner_id: a.resource_owner.clone(),
                ..Default::default()
            })
            .collect();
        wire::serialize_get_ipam_address_history_response(&GetIpamAddressHistoryResult {
            history_records: Some(IpamAddressHistoryRecordSet { items }),
            next_token: None,
        })
    }

