    #[cfg(feature = "network")]
    async fn handle_get_ipam_resource_cidrs(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{IpamResourceCidr, IpamResourceCidrSet};
        // Optional filter by IPAM pool.
        let pool_filter = params.get("IpamPoolId").cloned();
        let scope_filter = params.get("IpamScopeId").cloned();
        let st = state.read().await;
        // Build an index: pool_id -> (ipam_id, ipam_scope_id) so we can fill the
        // resource-cidr scope/ipam fields for each allocation.
        let scope_by_arn: HashMap<&String, &crate::types::IpamScope> = st
            .ipam_scopes
            .values()
            .map(|s| (&s.ipam_scope_arn, s))
            .collect();
        let mut items: Vec<IpamResourceCidr> = Vec::new();
        for ((pid, _aid), alloc) in st.ipam_pool_allocations.iter() {
            if let Some(want) = &pool_filter {
                if want != pid {
                    continue;
                }
            }
            let pool = match st.ipam_pools.get(pid) {
                Some(p) => p,
                None => continue,
            };
            let scope = scope_by_arn.get(&pool.ipam_scope_arn);
            if let Some(want_scope) = &scope_filter {
                let scope_id = scope.map(|s| &s.ipam_scope_id);
                if scope_id != Some(want_scope) {
                    continue;
                }
            }
            items.push(IpamResourceCidr {
                resource_cidr: Some(alloc.cidr.clone()),
                resource_id: alloc.resource_id.clone(),
                resource_type: Some(alloc.resource_type.clone()),
                resource_region: alloc.resource_region.clone(),
                resource_owner_id: alloc.resource_owner.clone(),
                ipam_pool_id: Some(pool.ipam_pool_id.clone()),
                ipam_scope_id: scope.map(|s| s.ipam_scope_id.clone()),
                ipam_id: scope.map(|s| {
                    s.ipam_arn
                        .rsplit_once('/')
                        .map(|(_, id)| id.to_string())
                        .unwrap_or_default()
                }),
                ..Default::default()
            });
        }
        wire::serialize_get_ipam_resource_cidrs_response(&GetIpamResourceCidrsResult {
            ipam_resource_cidrs: Some(IpamResourceCidrSet { items }),
            next_token: None,
        })
    }

