    #[cfg(feature = "advanced-network")]
    async fn handle_export_client_vpn_client_configuration(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let endpoint_id = match params.get("ClientVpnEndpointId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'ClientVpnEndpointId'",
                );
            }
        };
        let st = state.read().await;
        let ep = match st.client_vpn_endpoints.get(&endpoint_id) {
            Some(e) => e,
            None => {
                return ec2_error_response(&Ec2Error::InvalidClientVpnEndpointNotFound(
                    endpoint_id,
                ));
            }
        };
        // Synthesise a minimal OpenVPN-style client config referencing endpoint
        // fields. This is not a real working config; it just demonstrates that
        // endpoint state is being read.
        let mut cfg = String::new();
        cfg.push_str("client\n");
        cfg.push_str("dev tun\n");
        cfg.push_str(&format!("proto {}\n", ep.transport_protocol));
        cfg.push_str(&format!("remote {} {}\n", ep.dns_name, ep.vpn_port));
        cfg.push_str("resolv-retry infinite\n");
        cfg.push_str("nobind\n");
        cfg.push_str("persist-key\n");
        cfg.push_str("persist-tun\n");
        cfg.push_str("remote-cert-tls server\n");
        cfg.push_str("cipher AES-256-GCM\n");
        cfg.push_str("verb 3\n");
        cfg.push_str(&format!(
            "# server-certificate: {}\n",
            ep.server_certificate_arn
        ));
        if !ep.dns_servers.is_empty() {
            for dns in &ep.dns_servers {
                cfg.push_str(&format!("# dhcp-option DNS {}\n", dns));
            }
        }
        wire::serialize_export_client_vpn_client_configuration_response(
            &ExportClientVpnClientConfigurationResult {
                client_configuration: Some(cfg),
            },
        )
    }

