    #[cfg(feature = "advanced-network")]
    async fn handle_search_transit_gateway_multicast_groups(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::TransitGatewayMulticastGroupList;
        let domain_id = match params.get("TransitGatewayMulticastDomainId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'TransitGatewayMulticastDomainId'",
                );
            }
        };
        // Optional name=group-ip-address filter.
        let filters = parse_filters(params);
        let group_ip_filter: Option<Vec<String>> = filters
            .iter()
            .find(|(n, _)| n == "group-ip-address")
            .map(|(_, vs)| vs.clone());
        let st = state.read().await;
        let mut items: Vec<crate::model::TransitGatewayMulticastGroup> = Vec::new();
        for ((dom, _grp, _eni), m) in st.tgw_multicast_group_members.iter() {
            if dom != &domain_id {
                continue;
            }
            if let Some(ref want) = group_ip_filter {
                if !want.iter().any(|v| v == &m.group_ip_address) {
                    continue;
                }
            }
            items.push(tgw_multicast_group_member_to_model(m));
        }
        for ((dom, _grp, _eni), s) in st.tgw_multicast_group_sources.iter() {
            if dom != &domain_id {
                continue;
            }
            if let Some(ref want) = group_ip_filter {
                if !want.iter().any(|v| v == &s.group_ip_address) {
                    continue;
                }
            }
            items.push(tgw_multicast_group_source_to_model(s));
        }
        wire::serialize_search_transit_gateway_multicast_groups_response(
            &SearchTransitGatewayMulticastGroupsResult {
                multicast_groups: Some(TransitGatewayMulticastGroupList { items }),
                next_token: None,
            },
        )
    }

    #[cfg(feature = "compute")]
    async fn handle_export_image(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::ExportTaskS3Location;
        let image_id = match params.get("ImageId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'ImageId'"),
        };
        let role_name = params
            .get("RoleName")
            .cloned()
            .unwrap_or_else(|| "vmimport".to_string());
        let s3_bucket = match params.get("S3ExportLocation.S3Bucket") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'S3ExportLocation.S3Bucket'",
                );
            }
        };
        let s3_prefix = params.get("S3ExportLocation.S3Prefix").cloned();
        let disk_image_format = params
            .get("DiskImageFormat")
            .cloned()
            .unwrap_or_else(|| "VMDK".to_string());
        let description = params.get("Description").cloned();
        let tags = parse_tag_specifications(params, "export-image-task");
        let mut st = state.write().await;
        let task = st
            .export_image(
                image_id.clone(),
                role_name.clone(),
                s3_bucket.clone(),
                s3_prefix.clone(),
                disk_image_format.clone(),
                description.clone(),
                tags,
            )
            .clone();
        wire::serialize_export_image_response(&ExportImageResult {
            description,
            disk_image_format: Some(disk_image_format),
            export_image_task_id: Some(task.export_image_task_id.clone()),
            image_id: Some(image_id),
            progress: Some(task.progress.clone()),
            role_name: Some(role_name),
            s3_export_location: Some(ExportTaskS3Location {
                s3_bucket: Some(s3_bucket),
                s3_prefix,
            }),
            status: Some(task.status.clone()),
            status_message: task.status_message.clone(),
            tags: if task.tags.is_empty() {
                None
            } else {
                Some(tags_to_model(&task.tags))
            },
        })
    }

