    #[cfg(feature = "network")]
    async fn handle_get_route_server_associations(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::RouteServerAssociationsList;
        let route_server_id = match params.get("RouteServerId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'RouteServerId'");
            }
        };
        // Note: a previous regression test exercises this with an unseeded
        // route-server ID and expects an empty list. So we don't refuse
        // unknown IDs here; we just return the matching associations.
        let st = state.read().await;
        let items: Vec<crate::model::RouteServerAssociation> = st
            .route_server_associations
            .values()
            .filter(|a| a.route_server_id == route_server_id)
            .map(route_server_association_to_model)
            .collect();
        wire::serialize_get_route_server_associations_response(&GetRouteServerAssociationsResult {
            route_server_associations: Some(RouteServerAssociationsList { items }),
        })
    }

    #[cfg(feature = "network")]
    async fn handle_get_route_server_propagations(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::RouteServerPropagationsList;
        let route_server_id = match params.get("RouteServerId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'RouteServerId'"),
        };
        let st = state.read().await;
        if !st.route_servers.contains_key(&route_server_id) {
            return ec2_error_response(&Ec2Error::InvalidRouteServerNotFound(route_server_id));
        }
        // Synthesise a propagation per (route_server, vpc) association — each
        // associated VPC's main route table is a candidate propagation target.
        let mut items: Vec<crate::model::RouteServerPropagation> = Vec::new();
        for ((rs, vpc), assoc) in st.route_server_associations.iter() {
            if rs != &route_server_id {
                continue;
            }
            let route_table_id = st
                .route_tables
                .values()
                .find(|rt| rt.vpc_id == *vpc && rt.associations.iter().any(|a| a.main))
                .map(|rt| rt.route_table_id.clone());
            items.push(crate::model::RouteServerPropagation {
                route_server_id: Some(route_server_id.clone()),
                route_table_id,
                state: Some(assoc.state.clone()),
            });
        }
        wire::serialize_get_route_server_propagations_response(&GetRouteServerPropagationsResult {
            route_server_propagations: Some(RouteServerPropagationsList { items }),
        })
    }

