    #[cfg(feature = "network")]
    async fn handle_get_vpc_resources_blocking_encryption_enforcement(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
    ) -> MockResponse {
        use crate::model::{
            VpcEncryptionNonCompliantResource, VpcEncryptionNonCompliantResourceList,
        };
        let st = state.read().await;
        // A VPC blocks encryption enforcement when no active encryption control
        // exists for it. We treat any VPC absent from the encryption-controls map
        // as a blocker.
        let controlled_vpcs: std::collections::HashSet<String> = st
            .vpc_encryption_controls
            .values()
            .map(|c| c.vpc_id.clone())
            .collect();
        let items: Vec<VpcEncryptionNonCompliantResource> = st
            .vpcs
            .keys()
            .filter(|vpc_id| !controlled_vpcs.contains(*vpc_id))
            .map(|vpc_id| VpcEncryptionNonCompliantResource {
                id: Some(vpc_id.clone()),
                r#type: Some("vpc".to_string()),
                is_excludable: Some(true),
                description: Some("VPC has no active encryption control".to_string()),
            })
            .collect();
        wire::serialize_get_vpc_resources_blocking_encryption_enforcement_response(
            &GetVpcResourcesBlockingEncryptionEnforcementResult {
                non_compliant_resources: Some(VpcEncryptionNonCompliantResourceList { items }),
                next_token: None,
            },
        )
    }

