    #[cfg(feature = "extras")]
    async fn handle_enable_fast_launch(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            FastLaunchLaunchTemplateSpecificationResponse, FastLaunchSnapshotConfigurationResponse,
        };
        let image_id = match params.get("ImageId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'ImageId'"),
        };
        let resource_type = params
            .get("ResourceType")
            .cloned()
            .unwrap_or_else(|| "snapshot".to_string());
        let target_resource_count = params
            .get("SnapshotConfiguration.TargetResourceCount")
            .and_then(|s| s.parse::<i32>().ok());
        let max_parallel_launches = params
            .get("MaxParallelLaunches")
            .and_then(|s| s.parse::<i32>().ok())
            .unwrap_or(6);
        let launch_template_id = params.get("LaunchTemplate.LaunchTemplateId").cloned();
        let launch_template_name = params.get("LaunchTemplate.LaunchTemplateName").cloned();
        let version = params.get("LaunchTemplate.Version").cloned();
        let mut st = state.write().await;
        match st.enable_fast_launch(
            &image_id,
            resource_type,
            target_resource_count,
            max_parallel_launches,
            launch_template_id,
            launch_template_name,
            version,
            DEFAULT_ACCOUNT_ID.to_string(),
        ) {
            Ok(fl) => {
                let result = EnableFastLaunchResult {
                    image_id: Some(fl.image_id.clone()),
                    launch_template: Some(FastLaunchLaunchTemplateSpecificationResponse {
                        launch_template_id: fl.launch_template.launch_template_id.clone(),
                        launch_template_name: fl.launch_template.launch_template_name.clone(),
                        version: fl.launch_template.version.clone(),
                    }),
                    max_parallel_launches: Some(fl.max_parallel_launches),
                    owner_id: Some(fl.owner_id.clone()),
                    resource_type: Some(fl.resource_type.clone()),
                    snapshot_configuration: Some(FastLaunchSnapshotConfigurationResponse {
                        target_resource_count: fl.snapshot_configuration.target_resource_count,
                    }),
                    state: Some(fl.state.clone()),
                    state_transition_reason: Some("UserInitiated".to_string()),
                    state_transition_time: Some(fl.state_transition_time.clone()),
                };
                wire::serialize_enable_fast_launch_response(&result)
            }
            Err(e) => ec2_error_response(&e),
        }
    }

