    #[cfg(feature = "network")]
    async fn handle_disable_address_transfer(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::AddressTransfer as ModelAddressTransfer;
        let allocation_id = match params.get("AllocationId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'AllocationId'"),
        };
        let mut st = state.write().await;
        let eip = match st.elastic_ips.get_mut(&allocation_id) {
            Some(e) => e,
            None => {
                return ec2_error_response(&Ec2Error::AllocationNotFound(allocation_id));
            }
        };
        if eip.pending_transfer.is_none() {
            return ec2_error_response(&Ec2Error::InvalidAddressTransferNotFound(allocation_id));
        }
        eip.pending_transfer = None;
        let public_ip = eip.public_ip.clone();
        wire::serialize_disable_address_transfer_response(&DisableAddressTransferResult {
            address_transfer: Some(ModelAddressTransfer {
                allocation_id: Some(allocation_id),
                public_ip: Some(public_ip),
                address_transfer_status: Some("disabled".to_string()),
                ..Default::default()
            }),
        })
    }

