    #[cfg(feature = "network")]
    async fn handle_enable_aws_network_performance_metric_subscription(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::types::AwsNetworkPerformanceSubscription;
        let source = params.get("Source").cloned().unwrap_or_default();
        let destination = params.get("Destination").cloned().unwrap_or_default();
        let metric = params
            .get("Metric")
            .cloned()
            .unwrap_or_else(|| "aggregate-latency".to_string());
        let statistic = params
            .get("Statistic")
            .cloned()
            .unwrap_or_else(|| "p50".to_string());
        let key = (
            source.clone(),
            destination.clone(),
            metric.clone(),
            statistic.clone(),
        );
        let sub = AwsNetworkPerformanceSubscription {
            source,
            destination,
            metric,
            statistic,
            period: "five-minutes".to_string(),
        };
        let mut st = state.write().await;
        st.aws_network_performance_subscriptions.insert(key, sub);
        wire::serialize_enable_aws_network_performance_metric_subscription_response(
            &EnableAwsNetworkPerformanceMetricSubscriptionResult { output: Some(true) },
        )
    }

    #[cfg(feature = "network")]
    async fn handle_enable_route_server_propagation(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::RouteServerPropagation;
        let route_server_id = match params.get("RouteServerId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'RouteServerId'"),
        };
        let route_table_id = match params.get("RouteTableId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'RouteTableId'"),
        };
        let mut st = state.write().await;
        let assoc = st
            .route_server_associations
            .values_mut()
            .find(|a| a.route_server_id == route_server_id);
        let assoc = match assoc {
            Some(a) => a,
            None => {
                return ec2_error_response(&Ec2Error::InvalidRouteServerNotFound(route_server_id));
            }
        };
        if !assoc.propagations.contains(&route_table_id) {
            assoc.propagations.push(route_table_id.clone());
        }
        wire::serialize_enable_route_server_propagation_response(
            &EnableRouteServerPropagationResult {
                route_server_propagation: Some(RouteServerPropagation {
                    route_server_id: Some(route_server_id),
                    route_table_id: Some(route_table_id),
                    state: Some("enabled".to_string()),
                }),
            },
        )
    }

