    async fn handle_enable_vgw_route_propagation(&self) -> MockResponse {
        wire::serialize_enable_vgw_route_propagation_response()
    }

    #[cfg(feature = "storage")]
    async fn handle_disable_fast_snapshot_restores(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
    ) -> MockResponse {
        use crate::model::{
            DisableFastSnapshotRestoreErrorItem, DisableFastSnapshotRestoreErrorSet,
            DisableFastSnapshotRestoreSuccessItem, DisableFastSnapshotRestoreSuccessSet,
        };
        let azs = parse_member_list(params, "AvailabilityZone");
        let snapshot_ids = parse_member_list(params, "SourceSnapshotId");
        let mut successful: Vec<DisableFastSnapshotRestoreSuccessItem> = Vec::new();
        let mut unsuccessful: Vec<DisableFastSnapshotRestoreErrorItem> = Vec::new();
        let mut st = state.write().await;
        for snap_id in &snapshot_ids {
            match st.snapshots.get_mut(snap_id) {
                Some(snap) => {
                    for az in &azs {
                        if let Some(state_entry) = snap
                            .fast_snapshot_restore_states
                            .iter_mut()
                            .find(|s| &s.availability_zone == az)
                        {
                            state_entry.state = "disabled".to_string();
                        } else {
                            snap.fast_snapshot_restore_states.push(
                                crate::types::FastSnapshotRestoreState {
                                    availability_zone: az.clone(),
                                    state: "disabled".to_string(),
                                },
                            );
                        }
                        successful.push(DisableFastSnapshotRestoreSuccessItem {
                            snapshot_id: Some(snap_id.clone()),
                            availability_zone: Some(az.clone()),
                            state: Some("disabled".to_string()),
                            owner_id: Some(account_id.to_string()),
                            ..Default::default()
                        });
                    }
                }
                None => {
                    unsuccessful.push(DisableFastSnapshotRestoreErrorItem {
                        snapshot_id: Some(snap_id.clone()),
                        ..Default::default()
                    });
                }
            }
        }
        wire::serialize_disable_fast_snapshot_restores_response(
            &DisableFastSnapshotRestoresResult {
                successful: Some(DisableFastSnapshotRestoreSuccessSet { items: successful }),
                unsuccessful: Some(DisableFastSnapshotRestoreErrorSet {
                    items: unsuccessful,
                }),
            },
        )
    }

