    #[cfg(feature = "storage")]
    async fn handle_copy_volumes(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{CopyVolumesResult, VolumeList};
        let mut source_ids = parse_member_list(params, "SourceVolumeId");
        if source_ids.is_empty() {
            // Some callers pass a single SourceVolumeId without a numeric suffix.
            if let Some(v) = params.get("SourceVolumeId") {
                source_ids.push(v.clone());
            }
        }
        if source_ids.is_empty() {
            return MockResponse::error(
                400,
                "MissingParameter",
                "Missing 'SourceVolumeId.N' or 'SourceVolumeId'",
            );
        }
        let tags = parse_tag_specifications(params, "volume");
        let mut st = state.write().await;
        match st.copy_volumes(&source_ids, tags) {
            Ok(new_ids) => {
                let volumes: Vec<crate::model::Volume> = new_ids
                    .iter()
                    .filter_map(|id| st.volumes.get(id).map(volume_to_model))
                    .collect();
                wire::serialize_copy_volumes_response(&CopyVolumesResult {
                    volumes: Some(VolumeList { items: volumes }),
                })
            }
            Err(e) => ec2_error_response(&e),
        }
    }

