    #[cfg(feature = "storage")]
    async fn handle_import_snapshot(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
    ) -> MockResponse {
        use crate::model::{ImportSnapshotResult, SnapshotTaskDetail, UserBucketDetails};
        let description = params.get("Description").cloned();
        let format = params.get("DiskContainer.Format").cloned();
        let url = params.get("DiskContainer.Url").cloned();
        let s3_bucket = params.get("DiskContainer.UserBucket.S3Bucket").cloned();
        let s3_key = params.get("DiskContainer.UserBucket.S3Key").cloned();
        let encrypted = params
            .get("Encrypted")
            .map(|s| s == "true")
            .unwrap_or(false);
        let kms_key_id = params.get("KmsKeyId").cloned();
        let tags = parse_tag_specifications(params, "import-snapshot-task");
        let mut st = state.write().await;
        let task = st
            .import_snapshot(
                description.clone(),
                format.clone(),
                url.clone(),
                s3_bucket.clone(),
                s3_key.clone(),
                encrypted,
                kms_key_id.clone(),
                account_id,
                tags.clone(),
            )
            .clone();
        let user_bucket =
            if task.user_bucket_s3_bucket.is_some() || task.user_bucket_s3_key.is_some() {
                Some(UserBucketDetails {
                    s3_bucket: task.user_bucket_s3_bucket.clone(),
                    s3_key: task.user_bucket_s3_key.clone(),
                })
            } else {
                None
            };
        let detail = SnapshotTaskDetail {
            description: task.description.clone(),
            disk_image_size: task.disk_image_size,
            encrypted: Some(task.encrypted),
            format: task.format.clone(),
            kms_key_id: task.kms_key_id.clone(),
            progress: Some("100".to_string()),
            snapshot_id: task.snapshot_id.clone(),
            status: Some(task.status.clone()),
            status_message: None,
            url: task.url.clone(),
            user_bucket,
        };
        wire::serialize_import_snapshot_response(&ImportSnapshotResult {
            description: task.description.clone(),
            import_task_id: Some(task.import_task_id.clone()),
            snapshot_task_detail: Some(detail),
            tags: if task.tags.is_empty() {
                None
            } else {
                Some(tags_to_model(&task.tags))
            },
        })
    }

