    #[cfg(feature = "extras")]
    async fn handle_associate_trunk_interface(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{AssociateTrunkInterfaceResult, TrunkInterfaceAssociation};
        let branch_id = match params.get("BranchInterfaceId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'BranchInterfaceId'");
            }
        };
        let trunk_id = match params.get("TrunkInterfaceId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'TrunkInterfaceId'");
            }
        };
        let vlan_id = params.get("VlanId").and_then(|s| s.parse().ok());
        let gre_key = params.get("GreKey").and_then(|s| s.parse().ok());
        let interface_protocol = if vlan_id.is_some() {
            "vlan".to_string()
        } else if gre_key.is_some() {
            "gre".to_string()
        } else {
            "vlan".to_string()
        };
        let client_token = params.get("ClientToken").cloned();
        let mut st = state.write().await;
        let assoc = st
            .associate_trunk_interface(
                branch_id,
                trunk_id,
                interface_protocol,
                vlan_id,
                gre_key,
                Tags::new(),
            )
            .clone();
        wire::serialize_associate_trunk_interface_response(&AssociateTrunkInterfaceResult {
            client_token,
            interface_association: Some(TrunkInterfaceAssociation {
                association_id: Some(assoc.association_id.clone()),
                branch_interface_id: Some(assoc.branch_interface_id.clone()),
                gre_key: assoc.gre_key,
                interface_protocol: Some(assoc.interface_protocol.clone()),
                tags: None,
                trunk_interface_id: Some(assoc.trunk_interface_id.clone()),
                vlan_id: assoc.vlan_id,
            }),
        })
    }

