    #[cfg(feature = "compute")]
    async fn handle_create_reserved_instances_listing(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{CreateReservedInstancesListingResult, ReservedInstancesListingList};
        let ri_id = params
            .get("ReservedInstancesId")
            .cloned()
            .unwrap_or_default();
        let instance_count = params
            .get("InstanceCount")
            .and_then(|s| s.parse().ok())
            .unwrap_or(1i32);
        let client_token = params.get("ClientToken").cloned();
        let mut price_schedules: Vec<crate::types::PriceSchedule> = Vec::new();
        let mut n = 1;
        loop {
            let term_key = format!("PriceSchedules.{n}.Term");
            match params.get(&term_key) {
                Some(t) => {
                    let term = t.parse::<i64>().unwrap_or(0);
                    let price = params
                        .get(&format!("PriceSchedules.{n}.Price"))
                        .and_then(|s| s.parse().ok())
                        .unwrap_or(0.0);
                    let currency = params
                        .get(&format!("PriceSchedules.{n}.CurrencyCode"))
                        .cloned()
                        .unwrap_or_else(|| "USD".to_string());
                    price_schedules.push(crate::types::PriceSchedule {
                        term,
                        price,
                        currency_code: currency,
                        active: true,
                    });
                    n += 1;
                }
                None => break,
            }
        }
        let tags = parse_tag_specifications(params, "reserved-instances-listing");
        let mut st = state.write().await;
        let listing = st.create_reserved_instances_listing(
            &ri_id,
            instance_count,
            price_schedules,
            client_token,
            tags,
        );
        wire::serialize_create_reserved_instances_listing_response(
            &CreateReservedInstancesListingResult {
                reserved_instances_listings: Some(ReservedInstancesListingList {
                    items: vec![reserved_instances_listing_to_model(listing)],
                }),
            },
        )
    }

    #[cfg(feature = "compute")]
    async fn handle_delete_queued_reserved_instances(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            DeleteQueuedReservedInstancesError, DeleteQueuedReservedInstancesResult,
            FailedQueuedPurchaseDeletion, FailedQueuedPurchaseDeletionSet,
            SuccessfulQueuedPurchaseDeletion, SuccessfulQueuedPurchaseDeletionSet,
        };
        let ids = parse_member_list(params, "ReservedInstancesId");
        let mut st = state.write().await;
        let (succ, fail) = st.delete_queued_reserved_instances(&ids);
        wire::serialize_delete_queued_reserved_instances_response(
            &DeleteQueuedReservedInstancesResult {
                successful_queued_purchase_deletions: Some(SuccessfulQueuedPurchaseDeletionSet {
                    items: succ
                        .into_iter()
                        .map(|id| SuccessfulQueuedPurchaseDeletion {
                            reserved_instances_id: Some(id),
                        })
                        .collect(),
                }),
                failed_queued_purchase_deletions: Some(FailedQueuedPurchaseDeletionSet {
                    items: fail
                        .into_iter()
                        .map(|id| FailedQueuedPurchaseDeletion {
                            error: Some(DeleteQueuedReservedInstancesError {
                                code: Some("NotFound".to_string()),
                                message: Some("Queued purchase not found".to_string()),
                            }),
                            reserved_instances_id: Some(id),
                        })
                        .collect(),
                }),
            },
        )
    }

