    #[cfg(feature = "compute")]
    async fn handle_modify_reserved_instances(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::ModifyReservedInstancesResult;
        let ri_ids = parse_member_list(params, "ReservedInstancesId");
        let client_token = params.get("ClientToken").cloned();
        let mut targets: Vec<crate::types::ReservedInstancesConfiguration> = Vec::new();
        let mut n = 1;
        loop {
            let key = format!("ReservedInstancesConfigurationSetItemType.{n}.InstanceType");
            if !params.contains_key(&key)
                && !params.contains_key(&format!(
                    "ReservedInstancesConfigurationSetItemType.{n}.AvailabilityZone"
                ))
                && !params.contains_key(&format!(
                    "ReservedInstancesConfigurationSetItemType.{n}.InstanceCount"
                ))
                && !params.contains_key(&format!(
                    "ReservedInstancesConfigurationSetItemType.{n}.Platform"
                ))
            {
                break;
            }
            targets.push(crate::types::ReservedInstancesConfiguration {
                availability_zone: params
                    .get(&format!(
                        "ReservedInstancesConfigurationSetItemType.{n}.AvailabilityZone"
                    ))
                    .cloned(),
                instance_count: params
                    .get(&format!(
                        "ReservedInstancesConfigurationSetItemType.{n}.InstanceCount"
                    ))
                    .and_then(|s| s.parse().ok()),
                instance_type: params.get(&key).cloned(),
                platform: params
                    .get(&format!(
                        "ReservedInstancesConfigurationSetItemType.{n}.Platform"
                    ))
                    .cloned(),
                scope: params
                    .get(&format!(
                        "ReservedInstancesConfigurationSetItemType.{n}.Scope"
                    ))
                    .cloned(),
            });
            n += 1;
        }
        let mut st = state.write().await;
        let id = st.modify_reserved_instances(ri_ids, targets, client_token);
        wire::serialize_modify_reserved_instances_response(&ModifyReservedInstancesResult {
            reserved_instances_modification_id: Some(id),
        })
    }

