    #[cfg(feature = "storage")]
    async fn handle_modify_fpga_image_attribute(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            FpgaImageAttribute, LoadPermission as ModelLoadPermission, LoadPermissionList,
            ModifyFpgaImageAttributeResult,
        };
        let id = match params.get("FpgaImageId") {
            Some(v) => v.clone(),
            None => return MockResponse::error(400, "MissingParameter", "Missing 'FpgaImageId'"),
        };
        let name = params.get("Name").cloned();
        let description = params.get("Description").cloned();
        let mut add_load = Vec::new();
        let mut n = 1;
        loop {
            let user_key = format!("LoadPermission.Add.{n}.UserId");
            let group_key = format!("LoadPermission.Add.{n}.Group");
            if let Some(u) = params.get(&user_key) {
                add_load.push(("user_id".to_string(), u.clone()));
                n += 1;
            } else if let Some(g) = params.get(&group_key) {
                add_load.push(("group".to_string(), g.clone()));
                n += 1;
            } else {
                break;
            }
        }
        let mut remove_load = Vec::new();
        let mut n = 1;
        loop {
            let user_key = format!("LoadPermission.Remove.{n}.UserId");
            let group_key = format!("LoadPermission.Remove.{n}.Group");
            if let Some(u) = params.get(&user_key) {
                remove_load.push(("user_id".to_string(), u.clone()));
                n += 1;
            } else if let Some(g) = params.get(&group_key) {
                remove_load.push(("group".to_string(), g.clone()));
                n += 1;
            } else {
                break;
            }
        }
        let mut st = state.write().await;
        match st.modify_fpga_image_attribute(&id, name, description, add_load, remove_load) {
            Ok(img) => {
                let load_perms: Vec<ModelLoadPermission> = img
                    .load_permissions
                    .iter()
                    .map(|(s, v)| {
                        if s == "group" {
                            ModelLoadPermission {
                                group: Some(v.clone()),
                                user_id: None,
                            }
                        } else {
                            ModelLoadPermission {
                                user_id: Some(v.clone()),
                                group: None,
                            }
                        }
                    })
                    .collect();
                wire::serialize_modify_fpga_image_attribute_response(
                    &ModifyFpgaImageAttributeResult {
                        fpga_image_attribute: Some(FpgaImageAttribute {
                            fpga_image_id: Some(img.fpga_image_id.clone()),
                            name: Some(img.name.clone()),
                            description: img.description.clone(),
                            load_permissions: Some(LoadPermissionList { items: load_perms }),
                            product_codes: None,
                        }),
                    },
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

    #[cfg(feature = "compute")]
    async fn handle_replace_image_criteria_in_allowed_images_settings(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::ReplaceImageCriteriaInAllowedImagesSettingsResult;
        let mut criteria: Vec<crate::types::AllowedImageCriterion> = Vec::new();
        let mut n = 1;
        loop {
            let providers_first = format!("ImageCriterion.{n}.ImageProvider.1");
            let market_first = format!("ImageCriterion.{n}.MarketplaceProductCode.1");
            let depr_key = format!("ImageCriterion.{n}.DeprecationTimeCondition");
            if !params.contains_key(&providers_first)
                && !params.contains_key(&market_first)
                && !params.contains_key(&depr_key)
            {
                break;
            }
            let mut providers = Vec::new();
            let mut p = 1;
            while let Some(v) = params.get(&format!("ImageCriterion.{n}.ImageProvider.{p}")) {
                providers.push(v.clone());
                p += 1;
            }
            let mut market = Vec::new();
            let mut m = 1;
            while let Some(v) =
                params.get(&format!("ImageCriterion.{n}.MarketplaceProductCode.{m}"))
            {
                market.push(v.clone());
                m += 1;
            }
            criteria.push(crate::types::AllowedImageCriterion {
                image_providers: providers,
                marketplace_product_codes: market,
                deprecation_time_condition: params.get(&depr_key).cloned(),
            });
            n += 1;
        }
        let mut st = state.write().await;
        st.replace_allowed_image_criteria(criteria);
        wire::serialize_replace_image_criteria_in_allowed_images_settings_response(
            &ReplaceImageCriteriaInAllowedImagesSettingsResult {
                return_value: Some(true),
            },
        )
    }

