    #[cfg(feature = "compute")]
    async fn handle_modify_instance_credit_specification(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            ModifyInstanceCreditSpecificationResult, SuccessfulInstanceCreditSpecificationItem,
            SuccessfulInstanceCreditSpecificationSet, UnsuccessfulInstanceCreditSpecificationItem,
            UnsuccessfulInstanceCreditSpecificationSet,
        };
        let mut specs = Vec::new();
        let mut n = 1;
        loop {
            let id_key = format!("InstanceCreditSpecification.{n}.InstanceId");
            let credits_key = format!("InstanceCreditSpecification.{n}.CpuCredits");
            match (params.get(&id_key), params.get(&credits_key)) {
                (Some(id), Some(credits)) => {
                    specs.push((id.clone(), credits.clone()));
                    n += 1;
                }
                _ => break,
            }
        }
        let mut st = state.write().await;
        let (succ, fail) = st.modify_instance_credit_specification(&specs);
        wire::serialize_modify_instance_credit_specification_response(
            &ModifyInstanceCreditSpecificationResult {
                successful_instance_credit_specifications: Some(
                    SuccessfulInstanceCreditSpecificationSet {
                        items: succ
                            .into_iter()
                            .map(|id| SuccessfulInstanceCreditSpecificationItem {
                                instance_id: Some(id),
                            })
                            .collect(),
                    },
                ),
                unsuccessful_instance_credit_specifications: Some(
                    UnsuccessfulInstanceCreditSpecificationSet {
                        items: fail
                            .into_iter()
                            .map(|id| UnsuccessfulInstanceCreditSpecificationItem {
                                instance_id: Some(id),
                                error: None,
                            })
                            .collect(),
                    },
                ),
            },
        )
    }

