    #[cfg(feature = "compute")]
    async fn handle_create_instance_event_window(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::CreateInstanceEventWindowResult;
        let name = params.get("Name").cloned();
        let cron_expression = params.get("CronExpression").cloned();
        let mut time_ranges = Vec::new();
        let mut n = 1;
        loop {
            let sw = format!("TimeRange.{n}.StartWeekDay");
            let sh = format!("TimeRange.{n}.StartHour");
            let ew = format!("TimeRange.{n}.EndWeekDay");
            let eh = format!("TimeRange.{n}.EndHour");
            if !params.contains_key(&sw)
                && !params.contains_key(&sh)
                && !params.contains_key(&ew)
                && !params.contains_key(&eh)
            {
                break;
            }
            time_ranges.push(crate::types::InstanceEventWindowTimeRange {
                start_week_day: params.get(&sw).cloned(),
                start_hour: params.get(&sh).and_then(|s| s.parse().ok()),
                end_week_day: params.get(&ew).cloned(),
                end_hour: params.get(&eh).and_then(|s| s.parse().ok()),
            });
            n += 1;
        }
        let tags = parse_tag_specifications(params, "instance-event-window");
        let mut st = state.write().await;
        let win = st.create_instance_event_window(name, time_ranges, cron_expression, tags);
        wire::serialize_create_instance_event_window_response(&CreateInstanceEventWindowResult {
            instance_event_window: Some(instance_event_window_to_model(win)),
        })
    }

