    #[cfg(feature = "compute")]
    async fn handle_modify_instance_event_window(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::ModifyInstanceEventWindowResult;
        let id = match params.get("InstanceEventWindowId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'InstanceEventWindowId'",
                );
            }
        };
        let name = params.get("Name").cloned();
        let cron_expression = params.get("CronExpression").cloned();
        let mut time_ranges_buf = Vec::new();
        let mut has_tr = false;
        let mut n = 1;
        loop {
            let sw = format!("TimeRange.{n}.StartWeekDay");
            let sh = format!("TimeRange.{n}.StartHour");
            let ew = format!("TimeRange.{n}.EndWeekDay");
            let eh = format!("TimeRange.{n}.EndHour");
            if !params.contains_key(&sw)
                && !params.contains_key(&sh)
                && !params.contains_key(&ew)
                && !params.contains_key(&eh)
            {
                break;
            }
            has_tr = true;
            time_ranges_buf.push(crate::types::InstanceEventWindowTimeRange {
                start_week_day: params.get(&sw).cloned(),
                start_hour: params.get(&sh).and_then(|s| s.parse().ok()),
                end_week_day: params.get(&ew).cloned(),
                end_hour: params.get(&eh).and_then(|s| s.parse().ok()),
            });
            n += 1;
        }
        let time_ranges = if has_tr { Some(time_ranges_buf) } else { None };
        let mut st = state.write().await;
        match st.modify_instance_event_window(&id, name, time_ranges, cron_expression) {
            Ok(win) => wire::serialize_modify_instance_event_window_response(
                &ModifyInstanceEventWindowResult {
                    instance_event_window: Some(instance_event_window_to_model(win)),
                },
            ),
            Err(e) => ec2_error_response(&e),
        }
    }

