    #[cfg(feature = "compute")]
    async fn handle_delete_launch_template_versions(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{
            DeleteLaunchTemplateVersionsResponseErrorItem,
            DeleteLaunchTemplateVersionsResponseErrorSet,
            DeleteLaunchTemplateVersionsResponseSuccessItem,
            DeleteLaunchTemplateVersionsResponseSuccessSet, DeleteLaunchTemplateVersionsResult,
            ResponseError,
        };
        let lt_id = params
            .get("LaunchTemplateId")
            .cloned()
            .or_else(|| params.get("LaunchTemplateName").cloned())
            .unwrap_or_default();
        let versions: Vec<i64> = parse_member_list(params, "LaunchTemplateVersion")
            .into_iter()
            .filter_map(|s| s.parse().ok())
            .collect();
        let mut st = state.write().await;
        match st.delete_launch_template_versions(&lt_id, &versions) {
            Ok((succ, fail)) => {
                let lt = st
                    .launch_templates
                    .values()
                    .find(|lt| lt.launch_template_id == lt_id || lt.launch_template_name == lt_id)
                    .cloned();
                let (lt_id_resp, lt_name_resp) = match lt {
                    Some(lt) => (Some(lt.launch_template_id), Some(lt.launch_template_name)),
                    None => (Some(lt_id), None),
                };
                wire::serialize_delete_launch_template_versions_response(
                    &DeleteLaunchTemplateVersionsResult {
                        successfully_deleted_launch_template_versions: Some(
                            DeleteLaunchTemplateVersionsResponseSuccessSet {
                                items: succ
                                    .into_iter()
                                    .map(|v| DeleteLaunchTemplateVersionsResponseSuccessItem {
                                        launch_template_id: lt_id_resp.clone(),
                                        launch_template_name: lt_name_resp.clone(),
                                        version_number: Some(v),
                                    })
                                    .collect(),
                            },
                        ),
                        unsuccessfully_deleted_launch_template_versions: Some(
                            DeleteLaunchTemplateVersionsResponseErrorSet {
                                items: fail
                                    .into_iter()
                                    .map(|v| DeleteLaunchTemplateVersionsResponseErrorItem {
                                        launch_template_id: lt_id_resp.clone(),
                                        launch_template_name: lt_name_resp.clone(),
                                        response_error: Some(ResponseError {
                                            code: Some(
                                                "InvalidLaunchTemplateVersion.NotFound".to_string(),
                                            ),
                                            message: Some(format!("Version {v} does not exist")),
                                        }),
                                        version_number: Some(v),
                                    })
                                    .collect(),
                            },
                        ),
                    },
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

