    #[cfg(feature = "compute")]
    async fn handle_purchase_scheduled_instances(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        use crate::model::{PurchaseScheduledInstancesResult, PurchasedScheduledInstanceSet};
        let mut requests = Vec::new();
        let mut n = 1;
        loop {
            let dur_key = format!("PurchaseRequest.{n}.PurchaseToken");
            let count_key = format!("PurchaseRequest.{n}.InstanceCount");
            if !params.contains_key(&dur_key) && !params.contains_key(&count_key) {
                break;
            }
            requests.push(crate::state::ScheduledInstancePurchaseRequest {
                instance_type: "t3.micro".to_string(),
                platform: Some("Linux/UNIX".to_string()),
                network_platform: Some("EC2-VPC".to_string()),
                availability_zone: "us-east-1a".to_string(),
                instance_count: params
                    .get(&count_key)
                    .and_then(|s| s.parse().ok())
                    .unwrap_or(1),
                hourly_price: None,
                total_scheduled_instance_hours: 1500,
                recurrence: crate::types::ScheduledInstanceRecurrence::default(),
                slot_duration_in_hours: 24,
            });
            n += 1;
        }
        if requests.is_empty() {
            // At least one slot — use an empty default to avoid a malformed response.
            requests.push(crate::state::ScheduledInstancePurchaseRequest {
                instance_type: "t3.micro".to_string(),
                platform: Some("Linux/UNIX".to_string()),
                network_platform: Some("EC2-VPC".to_string()),
                availability_zone: "us-east-1a".to_string(),
                instance_count: 1,
                hourly_price: None,
                total_scheduled_instance_hours: 1500,
                recurrence: crate::types::ScheduledInstanceRecurrence::default(),
                slot_duration_in_hours: 24,
            });
        }
        let mut st = state.write().await;
        let purchased = st.purchase_scheduled_instances(requests);
        let items: Vec<crate::model::ScheduledInstance> =
            purchased.iter().map(scheduled_instance_to_model).collect();
        wire::serialize_purchase_scheduled_instances_response(&PurchaseScheduledInstancesResult {
            scheduled_instance_set: Some(PurchasedScheduledInstanceSet { items }),
        })
    }

