    #[cfg(feature = "advanced-network")]
    async fn handle_create_client_vpn_endpoint(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let client_cidr_block = match params.get("ClientCidrBlock") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'ClientCidrBlock'");
            }
        };
        let server_certificate_arn = match params.get("ServerCertificateArn") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'ServerCertificateArn'",
                );
            }
        };
        let description = params.get("Description").cloned();
        let dns_servers = parse_member_list(params, "DnsServers");
        let transport_protocol = params
            .get("TransportProtocol")
            .cloned()
            .unwrap_or_else(|| "udp".to_string());
        let vpn_port = params
            .get("VpnPort")
            .and_then(|v| v.parse().ok())
            .unwrap_or(443);
        let split_tunnel = params
            .get("SplitTunnel")
            .map(|s| s == "true")
            .unwrap_or(false);
        let mut authentication_options = Vec::new();
        // Walk AuthenticationOptions.member.N.Type
        for i in 1..32 {
            let key = format!("AuthenticationOptions.member.{i}.Type");
            if let Some(t) = params.get(&key) {
                authentication_options.push(t.clone());
            }
        }
        let connection_log_options_enabled = params
            .get("ConnectionLogOptions.Enabled")
            .map(|s| s == "true")
            .unwrap_or(false);
        let connection_log_options_cloudwatch_log_group = params
            .get("ConnectionLogOptions.CloudwatchLogGroup")
            .cloned();
        let connection_log_options_cloudwatch_log_stream = params
            .get("ConnectionLogOptions.CloudwatchLogStream")
            .cloned();
        let security_group_ids = parse_member_list(params, "SecurityGroupId");
        let vpc_id = params.get("VpcId").cloned();
        let self_service_portal = params
            .get("SelfServicePortal")
            .cloned()
            .unwrap_or_else(|| "disabled".to_string());
        let session_timeout_hours = params
            .get("SessionTimeoutHours")
            .and_then(|v| v.parse().ok())
            .unwrap_or(24);
        let client_login_banner_enabled = params
            .get("ClientLoginBannerOptions.Enabled")
            .map(|s| s == "true")
            .unwrap_or(false);
        let client_login_banner_text = params.get("ClientLoginBannerOptions.BannerText").cloned();
        let disconnect_on_session_timeout = params
            .get("DisconnectOnSessionTimeout")
            .map(|s| s == "true")
            .unwrap_or(false);
        let client_route_enforcement_enforced = params
            .get("ClientRouteEnforcementOptions.Enforced")
            .map(|s| s == "true")
            .unwrap_or(false);
        let tags = parse_tag_specifications(params, "client-vpn-endpoint");
        let mut st = state.write().await;
        let ep = st
            .create_client_vpn_endpoint(
                description,
                client_cidr_block,
                server_certificate_arn,
                dns_servers,
                transport_protocol,
                vpn_port,
                split_tunnel,
                authentication_options,
                connection_log_options_enabled,
                connection_log_options_cloudwatch_log_group,
                connection_log_options_cloudwatch_log_stream,
                security_group_ids,
                vpc_id,
                self_service_portal,
                session_timeout_hours,
                client_login_banner_enabled,
                client_login_banner_text,
                disconnect_on_session_timeout,
                client_route_enforcement_enforced,
                tags,
            )
            .clone();
        use crate::model::{ClientVpnEndpointStatus, CreateClientVpnEndpointResult};
        wire::serialize_create_client_vpn_endpoint_response(&CreateClientVpnEndpointResult {
            client_vpn_endpoint_id: Some(ep.client_vpn_endpoint_id.clone()),
            dns_name: Some(ep.dns_name.clone()),
            status: Some(ClientVpnEndpointStatus {
                code: Some(ep.status.code),
                message: ep.status.message,
            }),
        })
    }

