    #[cfg(feature = "advanced-network")]
    async fn handle_terminate_client_vpn_connections(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
    ) -> MockResponse {
        let endpoint_id = match params.get("ClientVpnEndpointId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'ClientVpnEndpointId'",
                );
            }
        };
        // The Smithy model exposes a single `ConnectionId` string ( the underlying
        // EC2 wire shape ), not a list. Some callers may still send `ConnectionId.N`
        // for forward-compat, so accept either form.
        let mut connection_ids = parse_member_list(params, "ConnectionId");
        if connection_ids.is_empty()
            && let Some(id) = params.get("ConnectionId")
        {
            connection_ids.push(id.clone());
        }
        let username = params.get("Username").cloned();
        let mut st = state.write().await;
        match st.terminate_client_vpn_connections(&endpoint_id, connection_ids, username.clone()) {
            Ok(rows) => {
                use crate::model::{
                    ClientVpnConnectionStatus, TerminateClientVpnConnectionsResult,
                    TerminateConnectionStatus, TerminateConnectionStatusSet,
                };
                let items: Vec<TerminateConnectionStatus> = rows
                    .into_iter()
                    .map(|(id, cur, prev)| TerminateConnectionStatus {
                        connection_id: Some(id),
                        current_status: Some(ClientVpnConnectionStatus {
                            code: Some(cur.code),
                            message: cur.message,
                        }),
                        previous_status: Some(ClientVpnConnectionStatus {
                            code: Some(prev.code),
                            message: prev.message,
                        }),
                    })
                    .collect();
                wire::serialize_terminate_client_vpn_connections_response(
                    &TerminateClientVpnConnectionsResult {
                        client_vpn_endpoint_id: Some(endpoint_id),
                        connection_statuses: Some(TerminateConnectionStatusSet { items }),
                        username,
                    },
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

