    #[cfg(feature = "advanced-network")]
    async fn handle_create_local_gateway_route(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
    ) -> MockResponse {
        let table_id = match params.get("LocalGatewayRouteTableId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'LocalGatewayRouteTableId'",
                );
            }
        };
        let cidr = match params.get("DestinationCidrBlock") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(
                    400,
                    "MissingParameter",
                    "Missing 'DestinationCidrBlock'",
                );
            }
        };
        let vif_group = params.get("LocalGatewayVirtualInterfaceGroupId").cloned();
        let eni = params.get("NetworkInterfaceId").cloned();
        let coip = params.get("CoipPoolId").cloned();
        let prefix = params.get("DestinationPrefixListId").cloned();
        let mut st = state.write().await;
        // Auto-seed the route table if the caller passed a pre-existing ID — real AWS
        // pre-creates LGW route tables for Outposts, so the typical TF flow does not call
        // CreateLocalGatewayRouteTable first.
        st.seed_local_gateway_route_table_with_id(&table_id, account_id);
        match st.create_local_gateway_route(
            &table_id, cidr, account_id, vif_group, eni, None, prefix, coip,
        ) {
            Ok(route) => {
                use crate::model::CreateLocalGatewayRouteResult;
                wire::serialize_create_local_gateway_route_response(
                    &CreateLocalGatewayRouteResult {
                        route: Some(local_gateway_route_to_model(route)),
                    },
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

    #[cfg(feature = "advanced-network")]
    async fn handle_create_local_gateway_route_table(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
    ) -> MockResponse {
        let local_gateway_id = match params.get("LocalGatewayId") {
            Some(v) => v.clone(),
            None => {
                return MockResponse::error(400, "MissingParameter", "Missing 'LocalGatewayId'");
            }
        };
        let mode = params.get("Mode").cloned();
        let tags = parse_tag_specifications(params, "local-gateway-route-table");
        let mut st = state.write().await;
        // Auto-seed the local gateway if it does not yet exist.
        if !st.local_gateways.contains_key(&local_gateway_id) {
            st.local_gateways.insert(
                local_gateway_id.clone(),
                crate::types::LocalGateway {
                    local_gateway_id: local_gateway_id.clone(),
                    outpost_arn: format!(
                        "arn:aws:outposts:us-east-1:{account_id}:outpost/op-injected"
                    ),
                    owner_id: account_id.to_string(),
                    state: "available".to_string(),
                    tags: crate::types::Tags::new(),
                },
            );
        }
        match st.create_local_gateway_route_table(&local_gateway_id, mode, account_id, tags) {
            Ok(t) => {
                use crate::model::CreateLocalGatewayRouteTableResult;
                wire::serialize_create_local_gateway_route_table_response(
                    &CreateLocalGatewayRouteTableResult {
                        local_gateway_route_table: Some(local_gateway_route_table_to_model(t)),
                    },
                )
            }
            Err(e) => ec2_error_response(&e),
        }
    }

