    #[cfg(feature = "extras")]
    async fn handle_create_ipam(
        &self,
        state: &Arc<tokio::sync::RwLock<Ec2State>>,
        params: &HashMap<String, String>,
        account_id: &str,
        region: &str,
    ) -> MockResponse {
        use crate::model::CreateIpamResult;
        let description = params.get("Description").cloned();
        let tier = params
            .get("Tier")
            .cloned()
            .unwrap_or_else(|| "advanced".to_string());
        let enable_private_gua = params
            .get("EnablePrivateGua")
            .map(|v| v == "true")
            .unwrap_or(false);
        let metered_account = params
            .get("MeteredAccount")
            .cloned()
            .unwrap_or_else(|| "ipam-owner".to_string());
        let operating_regions = parse_ipam_operating_regions(params, "OperatingRegion");
        let tags = parse_tag_specifications(params, "ipam");
        let mut st = state.write().await;
        let ipam = st.create_ipam(
            region,
            account_id,
            description,
            operating_regions,
            tier,
            enable_private_gua,
            metered_account,
            tags,
        );
        wire::serialize_create_ipam_response(&CreateIpamResult {
            ipam: Some(ipam_to_model(ipam)),
        })
    }

