#[cfg(feature = "advanced-network")]
fn vpn_connection_to_model(vpn: &crate::types::VpnConnection) -> crate::model::VpnConnection {
    use crate::model::{
        TunnelOption, TunnelOptionsList, VpnConnectionOptions as ModelVpnConnOpts,
        VpnStaticRoute as ModelVpnStaticRoute, VpnStaticRouteList,
    };
    let routes_model: Vec<ModelVpnStaticRoute> = vpn
        .routes
        .iter()
        .map(|r| ModelVpnStaticRoute {
            destination_cidr_block: Some(r.destination_cidr_block.clone()),
            source: Some(r.source.clone()),
            state: Some(r.state.clone()),
        })
        .collect();
    let options_model = vpn.options.as_ref().map(|o| ModelVpnConnOpts {
        local_ipv4_network_cidr: o.local_ipv4_network_cidr.clone(),
        local_ipv6_network_cidr: o.local_ipv6_network_cidr.clone(),
        remote_ipv4_network_cidr: o.remote_ipv4_network_cidr.clone(),
        remote_ipv6_network_cidr: o.remote_ipv6_network_cidr.clone(),
        tunnel_inside_ip_version: o.tunnel_inside_ip_version.clone(),
        static_routes_only: o.static_routes_only,
        tunnel_options: Some(TunnelOptionsList {
            items: o
                .tunnel_options
                .iter()
                .map(|t| TunnelOption {
                    tunnel_inside_cidr: t.tunnel_inside_cidr.clone(),
                    tunnel_inside_ipv6_cidr: t.tunnel_inside_ipv6_cidr.clone(),
                    pre_shared_key: t.pre_shared_key.clone(),
                    outside_ip_address: t.outside_ip_address.clone(),
                    ..Default::default()
                })
                .collect(),
        }),
        ..Default::default()
    });
    crate::model::VpnConnection {
        vpn_connection_id: Some(vpn.vpn_connection_id.clone()),
        vpn_gateway_id: Some(vpn.vpn_gateway_id.clone()),
        customer_gateway_id: Some(vpn.customer_gateway_id.clone()),
        transit_gateway_id: vpn.transit_gateway_id.clone(),
        r#type: Some(vpn.connection_type.clone()),
        state: Some(vpn.state.clone()),
        tags: if vpn.tags.is_empty() {
            None
        } else {
            Some(tags_to_model(&vpn.tags))
        },
        routes: if routes_model.is_empty() {
            None
        } else {
            Some(VpnStaticRouteList {
                items: routes_model,
            })
        },
        options: options_model,
        ..Default::default()
    }
}

