#[cfg(feature = "network")]
fn parse_nacl_entry(
    params: &HashMap<String, String>,
) -> Result<crate::types::NetworkAclEntry, String> {
    use crate::types::{IcmpTypeCode, PortRange};
    let rule_number: i32 = params
        .get("RuleNumber")
        .and_then(|v| v.parse().ok())
        .ok_or_else(|| "Missing 'RuleNumber'".to_string())?;
    let protocol = params
        .get("Protocol")
        .cloned()
        .ok_or_else(|| "Missing 'Protocol'".to_string())?;
    let rule_action = params
        .get("RuleAction")
        .cloned()
        .ok_or_else(|| "Missing 'RuleAction'".to_string())?;
    let egress = params.get("Egress").map(|v| v == "true").unwrap_or(false);
    let cidr_block = params.get("CidrBlock").cloned();
    let ipv6_cidr_block = params.get("Ipv6CidrBlock").cloned();
    let port_range = match (
        params
            .get("PortRange.From")
            .and_then(|v| v.parse::<i32>().ok()),
        params
            .get("PortRange.To")
            .and_then(|v| v.parse::<i32>().ok()),
    ) {
        (Some(from), Some(to)) => Some(PortRange { from, to }),
        _ => None,
    };
    let icmp_type_code = match (
        params.get("Icmp.Type").and_then(|v| v.parse::<i32>().ok()),
        params.get("Icmp.Code").and_then(|v| v.parse::<i32>().ok()),
    ) {
        (Some(type_num), Some(code)) => Some(IcmpTypeCode { type_num, code }),
        _ => None,
    };
    Ok(crate::types::NetworkAclEntry {
        rule_number,
        protocol,
        rule_action,
        egress,
        cidr_block,
        ipv6_cidr_block,
        port_range,
        icmp_type_code,
    })
}

#[cfg(feature = "network")]
fn parse_dhcp_configurations(
    params: &HashMap<String, String>,
) -> Vec<crate::types::DhcpConfiguration> {
    let mut configs = Vec::new();
    let mut n = 1;
    loop {
        let key_param = format!("DhcpConfiguration.{n}.Key");
        match params.get(&key_param) {
            Some(key) => {
                let mut values = Vec::new();
                let mut m = 1;
                loop {
                    let val_param = format!("DhcpConfiguration.{n}.Value.{m}");
                    match params.get(&val_param) {
                        Some(v) => {
                            values.push(v.clone());
                            m += 1;
                        }
                        None => break,
                    }
                }
                configs.push(crate::types::DhcpConfiguration {
                    key: key.clone(),
                    values,
                });
                n += 1;
            }
            None => break,
        }
    }
    configs
}

fn parse_query_string(s: &str) -> HashMap<String, String> {
    let mut map = HashMap::new();
    for pair in s.split('&') {
        if let Some((k, v)) = pair.split_once('=') {
            let key = urlencoding::decode(k)
                .unwrap_or(std::borrow::Cow::Borrowed(k))
                .to_string();
            let val = urlencoding::decode(v)
                .unwrap_or(std::borrow::Cow::Borrowed(v))
                .to_string();
            map.insert(key, val);
        }
    }
    map
}

fn parse_member_list(params: &HashMap<String, String>, prefix: &str) -> Vec<String> {
    let mut results = Vec::new();
    let mut i = 1;
    loop {
        let key = format!("{prefix}.{i}");
        match params.get(&key) {
            Some(v) => {
                results.push(v.clone());
                i += 1;
            }
            None => break,
        }
    }
    results
}

/// Collect `LaunchPermission.{Add|Remove}.N.{UserId|Group|OrganizationArn|OrganizationalUnitArn}`
/// entries from the awsQuery flat-key params.
#[cfg(feature = "compute")]
fn collect_launch_permissions(
    params: &HashMap<String, String>,
    sub: &str,
    out: &mut Vec<crate::types::LaunchPermission>,
) {
    let mut n = 1;
    loop {
        let prefix = format!("LaunchPermission.{sub}.{n}");
        let user_id = params.get(&format!("{prefix}.UserId")).cloned();
        let group = params.get(&format!("{prefix}.Group")).cloned();
        let org = params.get(&format!("{prefix}.OrganizationArn")).cloned();
        let ou = params
            .get(&format!("{prefix}.OrganizationalUnitArn"))
            .cloned();
        if user_id.is_none() && group.is_none() && org.is_none() && ou.is_none() {
            break;
        }
        // We only model user_id and group; other fields are accepted but ignored.
        out.push(crate::types::LaunchPermission { user_id, group });
        n += 1;
    }
}

fn parse_tag_specifications(params: &HashMap<String, String>, resource_type: &str) -> Tags {
    let mut tags = Tags::new();
    let mut n = 1;
    loop {
        let rt_key = format!("TagSpecification.{n}.ResourceType");
        match params.get(&rt_key) {
            Some(rt) if rt == resource_type => {
                let mut m = 1;
                loop {
                    let k = format!("TagSpecification.{n}.Tag.{m}.Key");
                    let v = format!("TagSpecification.{n}.Tag.{m}.Value");
                    match (params.get(&k), params.get(&v)) {
                        (Some(k), Some(v)) => {
                            tags.insert(k.clone(), v.clone());
                            m += 1;
                        }
                        _ => break,
                    }
                }
                n += 1;
            }
            Some(_) => {
                n += 1;
            }
            None => break,
        }
    }
    tags
}

fn parse_filters(params: &HashMap<String, String>) -> Vec<(String, Vec<String>)> {
    let mut filters = Vec::new();
    let mut n = 1;
    loop {
        let name_key = format!("Filter.{n}.Name");
        match params.get(&name_key) {
            Some(name) => {
                let mut values = Vec::new();
                let mut m = 1;
                loop {
                    let val_key = format!("Filter.{n}.Value.{m}");
                    match params.get(&val_key) {
                        Some(v) => {
                            values.push(v.clone());
                            m += 1;
                        }
                        None => break,
                    }
                }
                filters.push((name.clone(), values));
                n += 1;
            }
            None => break,
        }
    }
    filters
}

#[cfg(feature = "network")]
fn parse_ip_permissions(params: &HashMap<String, String>) -> Vec<IpPermission> {
    let mut rules = Vec::new();
    let mut n = 1;
    loop {
        let proto_key = format!("IpPermissions.{n}.IpProtocol");
        match params.get(&proto_key) {
            Some(proto) => {
                let from_port = params
                    .get(&format!("IpPermissions.{n}.FromPort"))
                    .and_then(|s| s.parse().ok());
                let to_port = params
                    .get(&format!("IpPermissions.{n}.ToPort"))
                    .and_then(|s| s.parse().ok());

                let mut ip_ranges = Vec::new();
                let mut m = 1;
                loop {
                    let cidr_key = format!("IpPermissions.{n}.IpRanges.{m}.CidrIp");
                    match params.get(&cidr_key) {
                        Some(cidr) => {
                            let desc = params
                                .get(&format!("IpPermissions.{n}.IpRanges.{m}.Description"))
                                .cloned();
                            ip_ranges.push(IpRange {
                                cidr_ip: cidr.clone(),
                                description: desc,
                            });
                            m += 1;
                        }
                        None => break,
                    }
                }

                let mut ipv6_ranges = Vec::new();
                let mut m = 1;
                loop {
                    let cidr_key = format!("IpPermissions.{n}.Ipv6Ranges.{m}.CidrIpv6");
                    match params.get(&cidr_key) {
                        Some(cidr) => {
                            let desc = params
                                .get(&format!("IpPermissions.{n}.Ipv6Ranges.{m}.Description"))
                                .cloned();
                            ipv6_ranges.push(Ipv6Range {
                                cidr_ipv6: cidr.clone(),
                                description: desc,
                            });
                            m += 1;
                        }
                        None => break,
                    }
                }

                let mut user_id_group_pairs = Vec::new();
                let mut m = 1;
                loop {
                    let gid_key = format!("IpPermissions.{n}.Groups.{m}.GroupId");
                    match params.get(&gid_key) {
                        Some(gid) => {
                            let uid = params
                                .get(&format!("IpPermissions.{n}.Groups.{m}.UserId"))
                                .cloned();
                            user_id_group_pairs.push(UserIdGroupPair {
                                group_id: gid.clone(),
                                user_id: uid,
                            });
                            m += 1;
                        }
                        None => break,
                    }
                }

                rules.push(IpPermission {
                    rule_id: String::new(),
                    from_port,
                    to_port,
                    ip_protocol: proto.clone(),
                    ip_ranges,
                    ipv6_ranges,
                    user_id_group_pairs,
                });
                n += 1;
            }
            None => break,
        }
    }
    rules
}

/// Apply filters to a resource, checking both specific fields and tag filters.
fn apply_filters_to_tags(
    tags: &Tags,
    filters: &[(String, Vec<String>)],
    fields: &[(&str, Option<&str>)],
) -> bool {
    for (name, values) in filters {
        // Check field filters
        if let Some((_, field_val)) = fields.iter().find(|(n, _)| *n == name.as_str())
            && let Some(fv) = field_val
        {
            if !values.contains(&fv.to_string()) {
                return false;
            }
            continue;
        }
        // Check tag filters: "tag:Key"
        if let Some(tag_key) = name.strip_prefix("tag:") {
            match tags.get(tag_key) {
                Some(tag_val) => {
                    if !values.contains(tag_val) {
                        return false;
                    }
                }
                None => return false,
            }
            continue;
        }
    }
    true
}

fn region_to_short(region: &str) -> String {
    // e.g. us-east-1 -> use1, eu-west-2 -> euw2
    let parts: Vec<&str> = region.split('-').collect();
    if parts.len() >= 3 {
        let continent = parts[0].chars().next().unwrap_or('u');
        let direction = parts[1].chars().next().unwrap_or('e');
        let num = parts[2];
        format!("{continent}{direction}{num}")
    } else {
        region.to_string()
    }
}

fn xml_escape(s: &str) -> String {
    s.replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
}

