#[cfg(feature = "network")]
fn access_scope_path_to_model(
    p: &crate::types::AccessScopePathSpec,
) -> crate::model::AccessScopePath {
    use crate::model::{
        PacketHeaderStatement, PathStatement, ProtocolList, ResourceStatement,
        ThroughResourcesStatement, ThroughResourcesStatementList, ValueStringList,
    };
    fn header_to_model(h: &crate::types::PacketHeaderStatementSpec) -> PacketHeaderStatement {
        PacketHeaderStatement {
            destination_addresses: Some(ValueStringList {
                items: h.destination_addresses.clone(),
            }),
            destination_ports: Some(ValueStringList {
                items: h.destination_ports.clone(),
            }),
            destination_prefix_lists: Some(ValueStringList {
                items: h.destination_prefix_lists.clone(),
            }),
            protocols: Some(ProtocolList {
                items: h.protocols.clone(),
            }),
            source_addresses: Some(ValueStringList {
                items: h.source_addresses.clone(),
            }),
            source_ports: Some(ValueStringList {
                items: h.source_ports.clone(),
            }),
            source_prefix_lists: Some(ValueStringList {
                items: h.source_prefix_lists.clone(),
            }),
        }
    }
    fn resource_to_model(r: &crate::types::ResourceStatementSpec) -> ResourceStatement {
        ResourceStatement {
            resource_types: Some(ValueStringList {
                items: r.resource_types.clone(),
            }),
            resources: Some(ValueStringList {
                items: r.resources.clone(),
            }),
        }
    }
    fn statement_to_model(s: &crate::types::PathStatementSpec) -> PathStatement {
        PathStatement {
            packet_header_statement: s.packet_header_statement.as_ref().map(header_to_model),
            resource_statement: s.resource_statement.as_ref().map(resource_to_model),
        }
    }
    let through: Vec<ThroughResourcesStatement> = p
        .through_resources
        .iter()
        .map(|rs| ThroughResourcesStatement {
            resource_statement: Some(resource_to_model(rs)),
        })
        .collect();
    crate::model::AccessScopePath {
        source: p.source.as_ref().map(statement_to_model),
        destination: p.destination.as_ref().map(statement_to_model),
        through_resources: Some(ThroughResourcesStatementList { items: through }),
    }
}

