#[cfg(feature = "compute")]
fn instance_event_window_to_model(
    win: &crate::types::InstanceEventWindow,
) -> crate::model::InstanceEventWindow {
    use crate::model::{
        DedicatedHostIdList, InstanceEventWindow as ModelWin, InstanceEventWindowAssociationTarget,
        InstanceEventWindowTimeRange as ModelTimeRange, InstanceEventWindowTimeRangeList,
        InstanceIdList,
    };
    let trs: Vec<ModelTimeRange> = win
        .time_ranges
        .iter()
        .map(|t| ModelTimeRange {
            end_hour: t.end_hour,
            end_week_day: t.end_week_day.clone(),
            start_hour: t.start_hour,
            start_week_day: t.start_week_day.clone(),
        })
        .collect();
    let assoc = win.association_target.as_ref().map(|a| {
        let tag_list = if a.tags.is_empty() {
            None
        } else {
            let mut t = crate::types::Tags::new();
            for (k, v) in &a.tags {
                t.insert(k.clone(), v.clone());
            }
            Some(tags_to_model(&t))
        };
        InstanceEventWindowAssociationTarget {
            instance_ids: Some(InstanceIdList {
                items: a.instance_ids.clone(),
            }),
            dedicated_host_ids: Some(DedicatedHostIdList {
                items: a.dedicated_host_ids.clone(),
            }),
            tags: tag_list,
        }
    });
    ModelWin {
        association_target: assoc,
        cron_expression: win.cron_expression.clone(),
        instance_event_window_id: Some(win.instance_event_window_id.clone()),
        name: Some(win.name.clone()),
        state: Some(win.state.clone()),
        tags: if win.tags.is_empty() {
            None
        } else {
            Some(tags_to_model(&win.tags))
        },
        time_ranges: Some(InstanceEventWindowTimeRangeList { items: trs }),
    }
}

