// ===== Group 6 helpers =====

#[cfg(feature = "network")]
fn parse_access_scope_paths(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Vec<crate::types::AccessScopePathSpec> {
    let mut out = Vec::new();
    let mut n = 1;
    loop {
        let p = format!("{prefix}.{n}");
        let source = parse_path_statement(params, &format!("{p}.Source"));
        let dest = parse_path_statement(params, &format!("{p}.Destination"));
        let through = {
            let mut v = Vec::new();
            let mut m = 1;
            loop {
                let r = parse_resource_statement(
                    params,
                    &format!("{p}.ThroughResource.{m}.ResourceStatement"),
                );
                if r.resources.is_empty() && r.resource_types.is_empty() {
                    break;
                }
                v.push(r);
                m += 1;
            }
            v
        };
        if source.is_none() && dest.is_none() && through.is_empty() {
            break;
        }
        out.push(crate::types::AccessScopePathSpec {
            source,
            destination: dest,
            through_resources: through,
        });
        n += 1;
    }
    out
}

#[cfg(feature = "network")]
fn parse_path_statement(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Option<crate::types::PathStatementSpec> {
    let phs = parse_packet_header_statement(params, &format!("{prefix}.PacketHeaderStatement"));
    let rs = parse_resource_statement(params, &format!("{prefix}.ResourceStatement"));
    let phs_is_some = !phs.destination_addresses.is_empty()
        || !phs.destination_ports.is_empty()
        || !phs.destination_prefix_lists.is_empty()
        || !phs.protocols.is_empty()
        || !phs.source_addresses.is_empty()
        || !phs.source_ports.is_empty()
        || !phs.source_prefix_lists.is_empty();
    let rs_is_some = !rs.resources.is_empty() || !rs.resource_types.is_empty();
    if !phs_is_some && !rs_is_some {
        return None;
    }
    Some(crate::types::PathStatementSpec {
        packet_header_statement: if phs_is_some { Some(phs) } else { None },
        resource_statement: if rs_is_some { Some(rs) } else { None },
    })
}

#[cfg(feature = "network")]
fn parse_packet_header_statement(
    params: &HashMap<String, String>,
    prefix: &str,
) -> crate::types::PacketHeaderStatementSpec {
    crate::types::PacketHeaderStatementSpec {
        destination_addresses: parse_member_list(params, &format!("{prefix}.DestinationAddress")),
        destination_ports: parse_member_list(params, &format!("{prefix}.DestinationPort")),
        destination_prefix_lists: parse_member_list(
            params,
            &format!("{prefix}.DestinationPrefixList"),
        ),
        protocols: parse_member_list(params, &format!("{prefix}.Protocol")),
        source_addresses: parse_member_list(params, &format!("{prefix}.SourceAddress")),
        source_ports: parse_member_list(params, &format!("{prefix}.SourcePort")),
        source_prefix_lists: parse_member_list(params, &format!("{prefix}.SourcePrefixList")),
    }
}

#[cfg(feature = "network")]
fn parse_resource_statement(
    params: &HashMap<String, String>,
    prefix: &str,
) -> crate::types::ResourceStatementSpec {
    crate::types::ResourceStatementSpec {
        resource_types: parse_member_list(params, &format!("{prefix}.ResourceType")),
        resources: parse_member_list(params, &format!("{prefix}.Resource")),
    }
}

#[cfg(feature = "network")]
fn parse_path_filter(
    params: &HashMap<String, String>,
    prefix: &str,
) -> crate::types::NetworkInsightsPathFilter {
    let parse_port_range = |p: &str| -> Option<crate::types::NetworkInsightsPathFilterPortRange> {
        let from = params
            .get(&format!("{p}.FromPort"))
            .and_then(|v| v.parse().ok());
        let to = params
            .get(&format!("{p}.ToPort"))
            .and_then(|v| v.parse().ok());
        if from.is_none() && to.is_none() {
            None
        } else {
            Some(crate::types::NetworkInsightsPathFilterPortRange {
                from_port: from,
                to_port: to,
            })
        }
    };
    crate::types::NetworkInsightsPathFilter {
        destination_address: params.get(&format!("{prefix}.DestinationAddress")).cloned(),
        destination_port_range: parse_port_range(&format!("{prefix}.DestinationPortRange")),
        source_address: params.get(&format!("{prefix}.SourceAddress")).cloned(),
        source_port_range: parse_port_range(&format!("{prefix}.SourcePortRange")),
    }
}

