#[cfg(feature = "compute")]
fn verified_access_instance_to_model(
    i: &crate::types::VerifiedAccessInstance,
    state: &Ec2State,
) -> crate::model::VerifiedAccessInstance {
    let condensed: Vec<_> = i
        .trust_provider_ids
        .iter()
        .filter_map(|tp_id| state.verified_access_trust_providers.get(tp_id))
        .map(verified_access_trust_provider_condensed)
        .collect();
    crate::model::VerifiedAccessInstance {
        verified_access_instance_id: Some(i.verified_access_instance_id.clone()),
        description: i.description.clone(),
        creation_time: Some(i.creation_time.clone()),
        last_updated_time: Some(i.last_updated_time.clone()),
        fips_enabled: Some(i.fips_enabled),
        cidr_endpoints_custom_sub_domain: i.cidr_endpoints_custom_subdomain.as_ref().map(|s| {
            crate::model::VerifiedAccessInstanceCustomSubDomain {
                sub_domain: Some(s.clone()),
                nameservers: None,
            }
        }),
        verified_access_trust_providers: if condensed.is_empty() {
            None
        } else {
            Some(condensed.into())
        },
        tags: if i.tags.is_empty() {
            None
        } else {
            Some(tags_to_model(&i.tags))
        },
    }
}

