#[cfg(feature = "extras")]
fn verified_access_endpoint_to_model(
    e: &crate::types::VerifiedAccessEndpoint,
) -> crate::model::VerifiedAccessEndpoint {
    use crate::model::{
        SecurityGroupIdList as ModelSgList, VerifiedAccessEndpointCidrOptions as ModelCidr,
        VerifiedAccessEndpointEniOptions as ModelEni,
        VerifiedAccessEndpointLoadBalancerOptions as ModelLb,
        VerifiedAccessEndpointPortRange as ModelPr,
        VerifiedAccessEndpointPortRangeList as ModelPrList,
        VerifiedAccessEndpointRdsOptions as ModelRds, VerifiedAccessEndpointStatus as ModelStatus,
        VerifiedAccessEndpointSubnetIdList as ModelSubList,
    };
    let convert_prs = |prs: &[crate::types::VerifiedAccessEndpointPortRange]| -> ModelPrList {
        ModelPrList {
            items: prs
                .iter()
                .map(|p| ModelPr {
                    from_port: p.from_port,
                    to_port: p.to_port,
                })
                .collect(),
        }
    };
    crate::model::VerifiedAccessEndpoint {
        verified_access_endpoint_id: Some(e.verified_access_endpoint_id.clone()),
        verified_access_instance_id: Some(e.verified_access_instance_id.clone()),
        verified_access_group_id: Some(e.verified_access_group_id.clone()),
        application_domain: e.application_domain.clone(),
        endpoint_type: Some(e.endpoint_type.clone()),
        attachment_type: Some(e.attachment_type.clone()),
        domain_certificate_arn: e.domain_certificate_arn.clone(),
        endpoint_domain: e.endpoint_domain.clone(),
        device_validation_domain: e.device_validation_domain.clone(),
        security_group_ids: if e.security_group_ids.is_empty() {
            None
        } else {
            Some(ModelSgList {
                items: e.security_group_ids.clone(),
            })
        },
        load_balancer_options: e.load_balancer_options.as_ref().map(|o| ModelLb {
            load_balancer_arn: o.load_balancer_arn.clone(),
            port: o.port,
            port_ranges: if o.port_ranges.is_empty() {
                None
            } else {
                Some(convert_prs(&o.port_ranges))
            },
            protocol: o.protocol.clone(),
            subnet_ids: if o.subnet_ids.is_empty() {
                None
            } else {
                Some(ModelSubList {
                    items: o.subnet_ids.clone(),
                })
            },
        }),
        network_interface_options: e.network_interface_options.as_ref().map(|o| ModelEni {
            network_interface_id: o.network_interface_id.clone(),
            port: o.port,
            port_ranges: if o.port_ranges.is_empty() {
                None
            } else {
                Some(convert_prs(&o.port_ranges))
            },
            protocol: o.protocol.clone(),
        }),
        cidr_options: e.cidr_options.as_ref().map(|o| ModelCidr {
            cidr: o.cidr.clone(),
            port_ranges: if o.port_ranges.is_empty() {
                None
            } else {
                Some(convert_prs(&o.port_ranges))
            },
            protocol: o.protocol.clone(),
            subnet_ids: if o.subnet_ids.is_empty() {
                None
            } else {
                Some(ModelSubList {
                    items: o.subnet_ids.clone(),
                })
            },
        }),
        rds_options: e.rds_options.as_ref().map(|o| ModelRds {
            port: o.port,
            protocol: o.protocol.clone(),
            rds_db_cluster_arn: o.rds_db_cluster_arn.clone(),
            rds_db_instance_arn: o.rds_db_instance_arn.clone(),
            rds_db_proxy_arn: o.rds_db_proxy_arn.clone(),
            rds_endpoint: o.rds_endpoint.clone(),
            subnet_ids: if o.subnet_ids.is_empty() {
                None
            } else {
                Some(ModelSubList {
                    items: o.subnet_ids.clone(),
                })
            },
        }),
        status: Some(ModelStatus {
            code: Some(e.status_code.clone()),
            message: e.status_message.clone(),
        }),
        creation_time: Some(e.creation_time.clone()),
        last_updated_time: Some(e.last_updated_time.clone()),
        deletion_time: e.deletion_time.clone(),
        description: e.description.clone(),
        sse_specification: Some(verified_access_sse_response(&e.sse_specification)),
        tags: if e.tags.is_empty() {
            None
        } else {
            Some(tags_to_model(&e.tags))
        },
    }
}

