#[cfg(feature = "extras")]
fn parse_oidc_options(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Option<crate::types::VerifiedAccessOidcOptions> {
    let issuer = params.get(&format!("{prefix}.Issuer")).cloned();
    let authorization_endpoint = params
        .get(&format!("{prefix}.AuthorizationEndpoint"))
        .cloned();
    let token_endpoint = params.get(&format!("{prefix}.TokenEndpoint")).cloned();
    let user_info_endpoint = params.get(&format!("{prefix}.UserInfoEndpoint")).cloned();
    let client_id = params.get(&format!("{prefix}.ClientId")).cloned();
    let client_secret = params.get(&format!("{prefix}.ClientSecret")).cloned();
    let scope = params.get(&format!("{prefix}.Scope")).cloned();
    if issuer.is_none()
        && authorization_endpoint.is_none()
        && token_endpoint.is_none()
        && user_info_endpoint.is_none()
        && client_id.is_none()
        && client_secret.is_none()
        && scope.is_none()
    {
        None
    } else {
        Some(crate::types::VerifiedAccessOidcOptions {
            issuer,
            authorization_endpoint,
            token_endpoint,
            user_info_endpoint,
            client_id,
            client_secret,
            scope,
        })
    }
}

#[cfg(feature = "extras")]
fn parse_modify_oidc_options(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Option<crate::types::VerifiedAccessOidcOptions> {
    parse_oidc_options(params, prefix)
}

