#[cfg(feature = "extras")]
fn parse_create_lb_options(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Option<crate::types::VerifiedAccessEndpointLoadBalancerOptions> {
    let lb = params.get(&format!("{prefix}.LoadBalancerArn")).cloned();
    let port = params
        .get(&format!("{prefix}.Port"))
        .and_then(|v| v.parse().ok());
    let protocol = params.get(&format!("{prefix}.Protocol")).cloned();
    let subnet_ids = parse_member_list(params, &format!("{prefix}.SubnetId"));
    let port_ranges = parse_port_ranges(params, &format!("{prefix}.PortRange"));
    if lb.is_none()
        && port.is_none()
        && protocol.is_none()
        && subnet_ids.is_empty()
        && port_ranges.is_empty()
    {
        None
    } else {
        Some(crate::types::VerifiedAccessEndpointLoadBalancerOptions {
            load_balancer_arn: lb,
            port,
            port_ranges,
            protocol,
            subnet_ids,
        })
    }
}

