#[cfg(feature = "extras")]
fn parse_port_ranges(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Vec<crate::types::VerifiedAccessEndpointPortRange> {
    let mut out = Vec::new();
    for n in 1..32 {
        let from_key = format!("{prefix}.{n}.FromPort");
        let to_key = format!("{prefix}.{n}.ToPort");
        let from = params.get(&from_key).and_then(|v| v.parse().ok());
        let to = params.get(&to_key).and_then(|v| v.parse().ok());
        if from.is_none() && to.is_none() {
            // Try also a slightly different shape.
            let from_alt = params.get(&format!("{prefix}.member.{n}.FromPort"));
            let to_alt = params.get(&format!("{prefix}.member.{n}.ToPort"));
            if from_alt.is_none() && to_alt.is_none() {
                break;
            }
            out.push(crate::types::VerifiedAccessEndpointPortRange {
                from_port: from_alt.and_then(|v| v.parse().ok()),
                to_port: to_alt.and_then(|v| v.parse().ok()),
            });
            continue;
        }
        out.push(crate::types::VerifiedAccessEndpointPortRange {
            from_port: from,
            to_port: to,
        });
    }
    out
}

#[cfg(feature = "compute")]
fn parse_log_options(
    params: &HashMap<String, String>,
    prefix: &str,
) -> crate::types::VerifiedAccessLogs {
    crate::types::VerifiedAccessLogs {
        cloud_watch_logs_enabled: params
            .get(&format!("{prefix}.CloudWatchLogs.Enabled"))
            .map(|v| v == "true")
            .unwrap_or(false),
        cloud_watch_logs_log_group: params
            .get(&format!("{prefix}.CloudWatchLogs.LogGroup"))
            .cloned(),
        kinesis_data_firehose_enabled: params
            .get(&format!("{prefix}.KinesisDataFirehose.Enabled"))
            .map(|v| v == "true")
            .unwrap_or(false),
        kinesis_data_firehose_delivery_stream: params
            .get(&format!("{prefix}.KinesisDataFirehose.DeliveryStream"))
            .cloned(),
        s3_enabled: params
            .get(&format!("{prefix}.S3.Enabled"))
            .map(|v| v == "true")
            .unwrap_or(false),
        s3_bucket_name: params.get(&format!("{prefix}.S3.BucketName")).cloned(),
        s3_bucket_owner: params.get(&format!("{prefix}.S3.BucketOwner")).cloned(),
        s3_prefix: params.get(&format!("{prefix}.S3.Prefix")).cloned(),
        log_version: params.get(&format!("{prefix}.LogVersion")).cloned(),
        include_trust_context: params
            .get(&format!("{prefix}.IncludeTrustContext"))
            .map(|v| v == "true"),
    }
}

// ----- Group 12: IPAM model conversion helpers and parse helpers -----

#[cfg(feature = "extras")]
fn parse_ipam_operating_regions(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Vec<crate::types::IpamOperatingRegion> {
    let mut out = Vec::new();
    let mut n = 1;
    loop {
        let key = format!("{prefix}.{n}.RegionName");
        match params.get(&key) {
            Some(v) => {
                out.push(crate::types::IpamOperatingRegion {
                    region_name: v.clone(),
                });
                n += 1;
            }
            None => break,
        }
    }
    out
}

#[cfg(feature = "extras")]
fn parse_ipam_operating_region_names(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Vec<String> {
    let mut out = Vec::new();
    let mut n = 1;
    loop {
        let key = format!("{prefix}.{n}.RegionName");
        match params.get(&key) {
            Some(v) => {
                out.push(v.clone());
                n += 1;
            }
            None => break,
        }
    }
    out
}

#[cfg(feature = "extras")]
fn parse_ipam_resource_tags(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Vec<(String, String)> {
    let mut out = Vec::new();
    let mut n = 1;
    loop {
        let key_k = format!("{prefix}.{n}.Key");
        let key_v = format!("{prefix}.{n}.Value");
        match (params.get(&key_k), params.get(&key_v)) {
            (Some(k), Some(v)) => {
                out.push((k.clone(), v.clone()));
                n += 1;
            }
            (Some(k), None) => {
                out.push((k.clone(), String::new()));
                n += 1;
            }
            _ => break,
        }
    }
    out
}

#[cfg(feature = "extras")]
fn parse_ipam_allocation_rules(
    params: &HashMap<String, String>,
    prefix: &str,
) -> Vec<crate::types::IpamPolicyAllocationRule> {
    let mut out = Vec::new();
    let mut n = 1;
    loop {
        let key = format!("{prefix}.{n}.SourceIpamPoolId");
        match params.get(&key) {
            Some(v) => {
                out.push(crate::types::IpamPolicyAllocationRule {
                    source_ipam_pool_id: Some(v.clone()),
                });
                n += 1;
            }
            None => break,
        }
    }
    out
}

